export const articleHtml: Record<string, string> = {
  "2026-06-24": "<div class=\"meta\"><span>2026-06-24</span><span class=\"sep\">·</span><span class=\"tag\">#SpaceX</span><span class=\"sep\">·</span><span class=\"tag\">#阿里巴巴</span><span class=\"sep\">·</span><span class=\"tag\">#OpenAI</span><span class=\"sep\">·</span><span class=\"tag\">#Anthropic</span><span class=\"sep\">·</span><span class=\"st\">status: parsed</span></div><figure class=\"cover-slot\"><img src=\"/covers/2026-06-24.jpg\" alt=\"SpaceX IPO 后两周再发首笔美元债，募资 250 亿美元，认购峰值近 900 亿 封面图\" loading=\"eager\" onload=\"this.closest('.cover-slot').classList.add('has-cover')\" onerror=\"this.closest('.cover-slot').classList.add('empty'); this.remove()\"><figcaption><span class=\"cover-k\">cover slot</span><span>上传封面图到 <code>public/covers/2026-06-24.jpg</code></span></figcaption></figure><h2 class=\"lead-title\">❯ SpaceX IPO 后两周再发首笔美元债，募资 250 亿美元，认购峰值近 900 亿</h2><p><code>[电报开局]</code> SpaceX 完成史上首笔美元投资级债券发行，<strong>最终募资 250 亿美元</strong>，较最初 200 亿美元的计划上调四分之一，距其创纪录的 IPO 还不到两周。据彭博报道，订单在认购高峰一度逼近 <strong>900 亿美元</strong>，定价时回落至 730 亿美元，仍是 AI 时代最大规模的公司债之一。</p>\n<p><code>[发行细节]</code> 这笔债拆成五档，期限横跨 <strong>2031 年到 2056 年</strong>，票息从 5.35% 一路爬到长端的 6.65%，承销阵容是美银、花旗、高盛、摩根大通和摩根士丹利五家。公司明确说，募来的钱先<strong>全额偿还过桥贷款</strong>，再付相关费用，余款作一般公司用途。就在发债前，SpaceX 还披露了超过 1000 亿美元的现金储备——刚靠 IPO 拿到一笔、手握千亿现金，却仍要再借 250 亿，胃口指向其 AI 与星链扩张的资本开支。横向看，甲骨文今年早些时候发了 250 亿美元债，亚马逊约 540 亿，Alphabet 约 315 亿，巨头们都在用债市给算力账单融资。</p>\n<p><code>[影响落点]</code> 真正被这笔债重新定价的，是市场对 SpaceX「不差钱」叙事的理解。一家刚 IPO、账上千亿现金的公司紧接着顶格借债，等于把<strong>未来几年的资本开支强度</strong>摊到了固定收益投资者面前。债券投资人接下来要盯的不再只是发射成功率，而是星链与 AI 基建的烧钱曲线能否被现金流追上；对同样排队融资的 AI 与航天公司来说，这场近 900 亿订单的超额认购，先给一级市场探了底。</p>\n<blockquote>\n<p><strong>signal ·</strong> 千亿现金还要再借 250 亿，押注的是资本开支会比现金流跑得更快。</p>\n</blockquote>\n<h2 id=\"-阿里巴巴起诉美国国防部要求移出涉军企业黑名单称违反正当程序\">❯ 阿里巴巴起诉美国国防部，要求移出涉军企业黑名单，称违反正当程序</h2>\n<p><code>[电报开局]</code> 阿里巴巴把美国国防部告上法庭，要求从「中国涉军企业」黑名单中除名，诉状本周二递交至<strong>加州圣何塞联邦法院</strong>。五角大楼在两周前的 6 月 8 日才把阿里加入名单，理由是其「与工信部存在关联、属于军民融合贡献方」，阿里则反击称这一认定<strong>「在事实和法律上均无依据」</strong>。</p>\n<p><code>[争议背景]</code> 阿里在诉状里强调，五角大楼<strong>未提供实质证据或解释</strong>就将其列入，做法违反美国宪法的正当程序条款，也侵犯其言论自由权利，并称公司由独立董事会治理、董事中无人有军方背景。此次列名发生在五角大楼 6 月 8 日把黑名单<strong>扩容到 188 家实体</strong>的大背景下，反映美方对中国军方借道民营科技获取技术的担忧。按现行美国法律，名单内企业自本月起不得与国防部签约，2027 年起连第三方采购其产品和服务也被禁止——这正是阿里赶在影响扩大前抢先起诉的紧迫所在。</p>\n<p><code>[影响落点]</code> 这桩诉讼把压力先压到了五角大楼的<strong>举证标准</strong>上：黑名单此前更像一纸行政标签，如今被告上法庭，国防部要在法院里拿出「军民融合」认定的事实依据。对其余 187 家在册中企而言，阿里能否打赢，等于替它们试探了这条<strong>司法救济路径</strong>走不走得通；对跨国合作的客户和供应商来说，要重新掂量的是与名单内企业往来在 2027 年禁令前后的合规风险。</p>\n<blockquote>\n<p><strong>signal ·</strong> 行政标签一旦进了法庭，比的就是国防部能不能把「军民融合」四个字落到证据上。</p>\n</blockquote>\n<h2 id=\"-阿里巴巴拟整体出售游戏业务灵犀互娱报价-70-亿至-90-亿元五家买方在谈\">❯ 阿里巴巴拟整体出售游戏业务灵犀互娱，报价 70 亿至 90 亿元，五家买方在谈</h2>\n<p><code>[电报开局]</code> 阿里巴巴正计划整体出售游戏品牌灵犀互娱，整体估值开在 <strong>70 亿至 90 亿元人民币</strong>，目前已对接至少五家潜在买方。据多家媒体报道，接触方包含三七互娱、中国儒意、世纪华通、巨人网络，以及两家<strong>抱团参与</strong>的私募股权巨头；新浪科技向阿里求证，截至发稿暂无回应。</p>\n<p><code>[交易细节]</code> 据多家媒体 <strong>6 月 23 日</strong>报道，灵犀互娱整体团队约 <strong>1200 人</strong>，此次交易据称打包旗下全部工作室与运营部门，涵盖平平无奇、南瓜、星辰、鸢、创新五个工作室，以及九游、交易猫两大运营板块。其中平平无奇工作室是核心自研团队，代表作正是阿里少有的爆款手游<strong>《三国志·战略版》</strong>，另有《三国志·战棋版》《忘却前夜》等。游戏此前曾被视为阿里多元化版图的一环，背景是 2025 年起阿里持续聚焦电商与云计算、剥离非核心资产，如今游戏业务被整体挂牌、报价 70 亿至 90 亿元，业内推测意在<strong>回笼现金流</strong>支撑集团核心业务。</p>\n<p><code>[影响落点]</code> 对接盘方来说，要算的是这 70 亿到 90 亿元买到的究竟是一条稳定现金牛，还是一支需要持续投入的研发团队：《三国志·战略版》的长线流水是估值锚，<strong>1200 人团队的留存</strong>则是风险点。对阿里自己，剥离游戏后真正被重排的是其内容与娱乐版图的边界；而对三七、世纪华通这些上市游戏公司，一旦接手，二级市场会立刻拿这笔收购重新校准它们的研发管线。</p>\n<blockquote>\n<p><strong>signal ·</strong> 这笔买卖的定价分歧，全在《三国志·战略版》的长线流水还能跑多久。</p>\n</blockquote>\n<h2 id=\"-minimax-首批限售股-7-月-9-日解禁阿里与米哈游两大股东表态不减持\">❯ MiniMax 首批限售股 7 月 9 日解禁，阿里与米哈游两大股东表态不减持</h2>\n<p><code>[电报开局]</code> AI 独角兽 MiniMax 将于 <strong>7 月 9 日</strong>迎来上市后首批限售股解禁，两大战略股东阿里巴巴与米哈游均明确表态<strong>长期看好、不减持</strong>。据 21 世纪经济报道独家，MiniMax 创始团队还自设了<strong>12 个月</strong>的自愿锁定期，远超行业惯例的 6 个月，且首批解禁不涉及创始团队与员工持股。</p>\n<p><code>[市场背景]</code> 解禁是新股上市后的常规压力测试——首批限售股松绑，往往引发早期投资人套现、股价承压。MiniMax 此前上市首日一度大涨超 60%，阿里、米哈游等投资方账面浮盈丰厚，市场原本担心解禁会触发抛压。两大股东主动喊话「持续陪伴」，阿里称将在<strong>云计算与企业服务</strong>层面深化生态协作，米哈游则强调通用人工智能是「未来十年最重要的技术变革力量」，会从基础技术到产业生态全面绑定。叠加创始团队 12 个月锁仓，等于在解禁窗口前给二级市场吃了颗定心丸。</p>\n<p><code>[影响落点]</code> 解禁日真正要看的，是「口头不减持」能不能转成持仓数据上的不动。对其他排队上市的 AI 公司，MiniMax 这套「大股东表态 + 创始团队超长锁仓」的组合拳，提供了一个可复制的预期管理模板；对二级市场投资者，接下来盯的不再是解禁本身，而是 <strong>7 月 9 日后阿里、米哈游的实际持股变动</strong>是否兑现了承诺。</p>\n<blockquote>\n<p><strong>signal ·</strong> 口头承诺管不管用，要等 7 月 9 日后的持股数据来兑现。</p>\n</blockquote>\n<h2 id=\"-openai-首登戛纳广告节向品牌主推-chatgpt-广告与-codex铺路-ipo\">❯ OpenAI 首登戛纳广告节，向品牌主推 ChatGPT 广告与 Codex，铺路 IPO</h2>\n<p><code>[电报开局]</code> OpenAI 首次亮相<strong>戛纳国际创意节</strong>，公开向品牌主和广告代理推销 ChatGPT 广告业务，并演示编程工具 Codex，直言<strong>「我们现在显然已经进入广告业」</strong>。据英国《金融时报》，这是 OpenAI 在 IPO 前冲刺数十亿美元新营收、正面叫板谷歌与 Meta 的关键一步。</p>\n<p><code>[业务细节]</code> OpenAI 在会上抛出两组抓手。其一是广告：约<strong>五分之一</strong>的 ChatGPT 查询带有明确商业意图，旅行、零售、健康美妆与金融服务的广告表现最强，公司已在美国等英语市场上线<strong>自助式广告平台</strong>，让中小企业直接买量。其二是把 Codex 重新包装给营销人——这款编程工具已达<strong>每周 500 万活跃用户</strong>，演示中被用来按指令生成营销活动所需的小工具和应用，使用场景从写代码外溢到创意策划与业务运营。两条线都指向同一个目标：在订阅收入之外，给即将上市的 OpenAI 撑起第二增长曲线。</p>\n<p><code>[影响落点]</code> OpenAI 一脚踏进广告业，最先被搅动的是谷歌和 Meta 把持的搜索广告预算。当五分之一的对话自带购买意图，广告主要重新规划的是把多少预算<strong>从传统搜索挪到对话入口</strong>；对 4A 与中小广告主，戛纳这场推介把「AI 是不是广告基础设施」的问题摆上了台面。而对 OpenAI 自己，广告与 Codex 能贡献多少真金白银，将直接写进它 IPO 招股书的营收故事里。</p>\n<blockquote>\n<p><strong>signal ·</strong> 五分之一对话带着购买意图，被重新分配的是谷歌和 Meta 手里的搜索预算。</p>\n</blockquote>\n<h2 id=\"-anthropic-推出-claude-tag把-slack-助手换成常驻-ai-同事企业版先用\">❯ Anthropic 推出 Claude Tag，把 Slack 助手换成常驻 AI 同事，企业版先用</h2>\n<p><code>[电报开局]</code> Anthropic 发布 <strong>Claude Tag</strong>，把原有的 Slack 助手升级成一个能记忆、会主动、可异步干活的「常驻 AI 同事」，即日起向 <strong>Claude 企业版与团队版</strong>用户开放公测。它直接替代旧版 Claude in Slack 应用，管理员有 <strong>30 天</strong>窗口选择迁移，旧应用将于 <strong>8 月 3 日</strong>退役。</p>\n<p><code>[功能细节]</code> 与只服务单个用户的旧助手不同，Claude Tag 在每个 Slack 频道里以<strong>一个共享实例</strong>存在：任何成员都能 @Claude 接力同事未完成的任务，它会沉淀频道历史与组织上下文形成<strong>持续记忆</strong>；开启「环境」模式后，还能不经提示主动跟进未解决的话题、推送相关更新。旧版 Claude in Slack 应用将于 <strong>8 月 3 日</strong>退役，管理员有 30 天迁移窗口。安全上，管理员可为每个实例界定可访问的工具、数据源和频道，设定组织级与频道级的<strong>月度 token 支出上限</strong>，并审计 Claude 执行过的每一项任务。Anthropic 称未来几周会把该能力扩展到其他平台，但未公布具体名单和时间表。</p>\n<p><code>[影响落点]</code> Claude Tag 把 AI 从「被调用的工具」推到了「频道里的固定一员」。对企业 IT 管理员，要重新规划的是<strong>权限边界与成本闸门</strong>——一个能自主行动、按频道计费的 Agent，审计和预算控制比模型本身更紧要。对协作软件赛道，Anthropic 选择寄生在 Slack 频道里，下一轮竞争的落点不在聊天框，而在谁能成为团队默认的那个「AI 工位」。</p>\n<blockquote>\n<p><strong>signal ·</strong> AI 从被 @ 的工具变成频道里的固定工位，管理员要先管住的是权限和账单。</p>\n</blockquote>\n<h2 id=\"-deepseek-组建-harness-团队抢人前-jane-street-工程师带队补-agent-短板\">❯ DeepSeek 组建 Harness 团队抢人，前 Jane Street 工程师带队补 Agent 短板</h2>\n<p><code>[电报开局]</code> DeepSeek 正加速扩张其新设的 <strong>Harness 团队</strong>，全力杀入 AI Agent 市场。据南华早报，团队负责人、今年 <strong>3 月</strong>加入的前<strong>量化交易公司 Jane Street</strong> 工程师崔天翼在 X 上坦言，这支新组建的队伍<strong>人才极度紧缺</strong>，他每天面试候选人、四处发招聘帖。</p>\n<p><code>[行业背景]</code> 崔天翼今年 3 月加入 DeepSeek 执掌 Harness 团队，岗位设在北京海淀的融科资讯中心，近期放出 Agent Harness 产品经理与研发工程师两个关键职位。所谓 harness，是把一个语言模型变成可用、能自主的 AI Agent 的<strong>关键软件基础设施</strong>——团队把使命直接概括为「模型 + Harness = Agent」，模型之外的工具调用、记忆、智能体循环、桌面集成、MCP 与反馈系统全归 Harness。这条产品线被外界视为直接对标 Anthropic 的 <strong>Claude Code</strong>：DeepSeek 此前以 V3、R1 模型打开局面，如今补的是「有好模型、缺好外壳」的短板。</p>\n<p><code>[影响落点]</code> DeepSeek 这轮抢人，暴露的是中国 AI 公司从「卷模型」转向「卷 Agent 工程」时共同的人才缺口。对求职的工程师，真正稀缺、议价权也最高的能力，正<strong>从训练模型转向把模型封装成能干活的产品</strong>；对同赛道的国产大模型厂商，要重新排序的是研发投入——再强的基座模型，没有趁手的 harness 也变不成商业化的自主 Agent。</p>\n<blockquote>\n<p><strong>signal ·</strong> 模型不再是瓶颈，能不能把模型封装成会干活的产品，才是这轮抢人的真正标的。</p>\n</blockquote>\n<h2 id=\"-字节跳动发布豆包大模型-21-pro日常功能继续免费另开专业版办公模式\">❯ 字节跳动发布豆包大模型 2.1 Pro，日常功能继续免费，另开专业版办公模式</h2>\n<p><code>[电报开局]</code> 字节跳动在火山引擎 Force 原动力大会上发布<strong>豆包大模型 2.1</strong>，分 Pro 与 Turbo 两档，官方称 <strong>2.1 Pro</strong> 在多项权威测评中得分接近或超越 GPT-5.5 与 Claude Opus 4.7。火山引擎总裁谭待同时表态，豆包<strong>日常功能继续免费</strong>，但将推出搭载 2.1 Pro 的<strong>专业版办公任务模式</strong>。</p>\n<p><code>[产品细节]</code> 谭待划出了一条免费与收费的分界线：搜索问答、写作生图、语音和视频对话等大众日常功能维持免费，面向生产力场景的专业版办公模式则单独收费。2.1 Pro 在 <strong>Coding 与 Agent 场景</strong>下表现据称大幅提升，已在火山引擎上线，面向企业和开发者开放 API，并陆续接入豆包、TRAE、扣子等应用。这是字节继 Seedance 视频模型后，同一场大会上对语言模型主线的更新，延续其「免费走量、专业版变现」的打法。</p>\n<p><code>[影响落点]</code> 豆包把「免费」与「专业办公」切开，要重新算账的是企业用户：哪些任务用免费版够、哪些值得为办公模式付费，成了采购决策的新一道题。对国产大模型同行，字节这套「C 端免费圈用户、B 端办公场景收钱」的分层，把竞争焦点从跑分推向了<strong>谁能在生产力场景里真正收上钱</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 跑分追平 GPT-5.5 之外，真正要回答的是办公模式能不能从企业手里收上钱。</p>\n</blockquote>\n<h2 id=\"-字节跳动发布-seedance-25单次生成-30-秒视频参考素材上限提到-50-份\">❯ 字节跳动发布 Seedance 2.5，单次生成 30 秒视频，参考素材上限提到 50 份</h2>\n<p><code>[电报开局]</code> 字节跳动在 6 月 23 日的火山引擎 Force 大会上发布 AI 视频模型 <strong>Seedance 2.5</strong>，单次可生成<strong>最长 30 秒</strong>的视频，参考素材上限从上一代的 12 份大幅提到 <strong>50 份</strong>。据 The Information，新模型生成的长片段无需后期拼接，自带场景切换与节奏变化。</p>\n<p><code>[技术细节]</code> Seedance 2.5 一次能吞下最多 50 个多模态输入，包括图像、音频、3D 白模和风格参考，适合<strong>多角色的影视镜头</strong>；同场还更新了支持 4K 输出的 Seedance 2.0。它是 Dreamina、豆包、剪映背后的视频引擎，目前面向全球企业开放 beta，公开发布瞄准 <strong>7 月初</strong>。横向对比，谷歌 Veo 仅支持 3 个参考输入，Seedance 2.5 的 50 份输入在专业工作流上拉开明显差距——参考素材的吞吐量，正成为 AI 视频从「出片」走向「可控创作」的新战场。</p>\n<p><code>[影响落点]</code> 30 秒和 50 份输入这两个数字，把竞争从「画质好不好」推向了「可不可控」。对影视与广告团队，能一次喂进 <strong>50 份参考</strong>、生成带场景切换的长镜头，可以据此重新规划分镜与素材管理流程；对 Veo 等对手，被改写的是参考输入这一项硬指标的及格线。</p>\n<blockquote>\n<p><strong>signal ·</strong> 真正被这次更新定价的，是参考素材吞吐量这条 AI 视频可控性的及格线。</p>\n</blockquote>\n<h2 id=\"-openai-新语音模型-bidi-1-实测流出能实时翻译还能唱歌拟声\">❯ OpenAI 新语音模型 Bidi 1 实测流出，能实时翻译、还能唱歌拟声</h2>\n<p><code>[电报开局]</code> OpenAI 正在开发的新一代语音模型 <strong>Bidi 1</strong> 多段实测样本流出，能<strong>实时翻译</strong>、还能唱歌和生成各种拟声。据科技媒体 TestingCatalog，相关代码与界面元素约在 <strong>6 月 16 日</strong>被发现于 ChatGPT 应用内，模型主打「边说边听、可被打断」的双向设计。</p>\n<p><code>[能力细节]</code> Bidi 1 的核心是双向（bidirectional）架构——能在用户说话时同时开口并保持倾听，可中途接收打断、即时改口，摆脱当前语音模式「暂停再重启」的生硬卡顿。翻译能力上与 OpenAI 已发布的 <strong>GPT-Realtime-Translate</strong> 一脉相承，后者可把 70 多种输入语言实时译成 13 种输出语言；创意能力则延续首代高级语音，唱歌、beatbox 都在，但版权处理更严，会直接拒绝翻唱热门歌曲、转而按指定风格原创。目前 Bidi 1 仍未正式发布，多账号互证但口径来自代码挖掘与样本流出，<strong>尚属上线前的泄露</strong>。</p>\n<p><code>[影响落点]</code> 一旦 Bidi 1 落到 API，最先被打开的是实时翻译这类长期卡在延迟上的场景。对语音应用开发者，要重新评估的是哪些「同声传译」「实时对话」产品此前因延迟做不成、如今能不能补上；对做 AI 语音的对手，被抬高的是<strong>「自然打断 + 实时翻译」这套体验门槛</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 把实时翻译从演示推向 API，被重新定义的是「同声传译」这类卡在延迟上的应用边界。</p>\n</blockquote>\n<h2 id=\"-anthropic-联创杰克克拉克ai-自造接班人-2028-年成真概率约六成\">❯ Anthropic 联创杰克·克拉克：AI 自造接班人 2028 年成真概率约六成</h2>\n<p><code>[电报开局]</code> Anthropic 联合创始人<strong>杰克·克拉克（Jack Clark）</strong>给出一个具体判断：到 <strong>2028 年底</strong>，AI 系统能在<strong>无人参与</strong>下训练出更强接班人的概率约为 <strong>60%</strong>，2027 年则约 30%。他强调这不是说 2028 年就有超级智能，而是「AI 显著改进 AI」的递归循环会在那个窗口内建立。</p>\n<p><code>[论据细节]</code> 据克拉克近期公开演讲，他的判断建立在一组陡峭的基准曲线上。在测真实 GitHub 问题的 SWE-Bench 上，成功率从 2023 年底 Claude 2 的约 <strong>2%</strong> 飙到 <strong>93.9%</strong>；METR 的「时间跨度」指标从 GPT-3.5 的约 30 秒爬到当下前沿模型的约 <strong>12 小时</strong>；Anthropic 一项内部测试要求模型优化纯 CPU 小模型的训练实现，平均加速比从 2025 年 5 月 Opus 4 的 <strong>2.9 倍</strong>涨到 2026 年 4 月的 <strong>52 倍</strong>。他此前就多次警告，一旦系统能自建接班人，对它们的监控、约束与对齐就变得空前重要——这也是他呼吁给递归自我改进「踩一脚刹车」的由来。</p>\n<p><code>[影响落点]</code> 克拉克把一个模糊的「智能爆炸」担忧，压成了一个带概率、带时间表的工程命题。对 AI 安全与监管者，要重新规划的是节奏——若递归循环真在 2028 年前后成形，<strong>治理框架的准备窗口只剩两三年</strong>；对整个行业，这番来自头部实验室联创的表态，把「该不该自我设限」从口号变成了一道摆在桌上的现实选择题。</p>\n<blockquote>\n<p><strong>signal ·</strong> 当「AI 造 AI」被标上 60% 和 2028 这两个数字，治理的准备窗口就只剩两三年。</p>\n</blockquote>",
  "2026-06-23": "<div class=\"meta\"><span>2026-06-23</span><span class=\"sep\">·</span><span class=\"tag\">#SpaceX</span><span class=\"sep\">·</span><span class=\"tag\">#ReflectionAI</span><span class=\"sep\">·</span><span class=\"tag\">#OpenAI</span><span class=\"sep\">·</span><span class=\"tag\">#GPT55Cyber</span><span class=\"sep\">·</span><span class=\"st\">status: parsed</span></div><figure class=\"cover-slot\"><img src=\"/covers/2026-06-23.jpg\" alt=\"SpaceX 与 Reflection AI 签最高 63 亿美元算力协议，公布当天自家股价重挫近 17% 跌破发行价 封面图\" loading=\"eager\" onload=\"this.closest('.cover-slot').classList.add('has-cover')\" onerror=\"this.closest('.cover-slot').classList.add('empty'); this.remove()\"><figcaption><span class=\"cover-k\">cover slot</span><span>上传封面图到 <code>public/covers/2026-06-23.jpg</code></span></figcaption></figure><h2 class=\"lead-title\">❯ SpaceX 与 Reflection AI 签最高 63 亿美元算力协议，公布当天自家股价重挫近 17% 跌破发行价</h2><p><code>[算力租约]</code> 据 CNBC 报道，SpaceX 与开源大模型公司 <strong>Reflection AI</strong> 签下一份最高 <strong>63 亿美元</strong>的算力租约：后者从 2026 年 7 月起按<strong>每月 1.5 亿美元</strong>付费、一直付到 2029 年，租用部署在 <strong>Colossus 2</strong> 数据中心的英伟达 GB300 芯片。协议见报当天，SpaceX 二级市场股价却<strong>暴跌近 17%</strong>，跌破 IPO 首日收盘价。</p>\n<p><code>[现金流换算力]</code> Reflection AI 是一家走开源路线的 AI 初创，此前以可自托管的开放权重模型为卖点。这份合同把它一举绑上 SpaceX 旗下、与 xAI 共用的算力底座——按每月 1.5 亿美元、连付约三年半折算，正好对上 <strong>63 亿美元</strong>的合同上限，是当前公开可见的开源阵营<strong>单笔最大算力采购</strong>之一。对 SpaceX 而言，这是把火箭与星链的现金流进一步导向 AI 数据中心：Colossus 2 正是其为承接 GB300 集群扩建的新一代园区。问题在于，市场并没有为这笔「稳定长约」鼓掌，反而当天就把股价砸到发行价以下。</p>\n<p><code>[股东重算账]</code> 同一天签下三年半锁定收入、股价却破发，说明投资者担心的不是订单有没有，而是 SpaceX 正在从一家火箭公司变成<strong>重资产的算力地主</strong>——GB300 采购、园区扩建、电力与折旧都要先垫钱，回收周期被拉长。对持有 SpaceX 的股东来说，接下来要盯的不再只是发射节奏和星链订户，而是这条<strong>算力业务线的资本开支</strong>会不会持续吃掉自由现金流。</p>\n<blockquote>\n<p><strong>signal ·</strong> 三年半的锁定收入没托住股价，市场为 SpaceX 重新定价的是它资产负债表上越堆越高的算力折旧。</p>\n</blockquote>\n<h2 id=\"-openai-发布升级版-gpt-55-cyber联手-trail-of-bits-启动开源漏洞修复计划-patch-the-planet\">❯ OpenAI 发布升级版 GPT-5.5-Cyber，联手 Trail of Bits 启动开源漏洞修复计划 Patch the Planet</h2>\n<p><code>[安全模型]</code> 据《连线》报道，OpenAI 推出升级版网络安全模型 <strong>GPT-5.5-Cyber</strong>，并联合安全审计公司 <strong>Trail of Bits</strong> 发起名为 <strong>Patch the Planet</strong> 的计划，目标是用模型批量发现并修复开源软件里的漏洞。据其披露，新版在 CyberGym 漏洞复现基准上的得分从早期版本的 <strong>81.9% 提升到 85.6%</strong>，Codex 也同步加挂了一个安全插件。</p>\n<p><code>[攻防同源]</code> CyberGym 衡量的是 AI 智能体能否独立复现已知软件漏洞——分数越高，模型既能用于防守端的漏洞排查，也具备<strong>更强的进攻潜力</strong>。这正是 OpenAI 这次同时端出能力升级与 <strong>Patch the Planet 修复计划</strong>的原因：用一个面向开源社区的公益修 bug 项目，给「网络安全专用模型」套上防御性叙事。背景是监管侧的警觉正在升温——本周有报道称，五眼联盟的网络机构警告，能大幅放大网络攻击的前沿模型「<strong>可能只剩数月</strong>」之遥。OpenAI 选择把高危能力和公开修复承诺捆在一起发布，时机上并非巧合。</p>\n<p><code>[谁要重审]</code> 把同一套漏洞复现能力同时摆上攻防两端，最先要重新评估的是<strong>开源项目维护者和企业安全团队</strong>：他们既可能因 Patch the Planet 拿到自动化的补丁援军，也要面对「同样的模型能被对手拿去复现漏洞」的现实。对监管者而言，一个跑到 <strong>85.6%</strong> 的 CyberGym 分数，会把「前沿模型该不该按网络武器管」的讨论从假设推向具体条款。</p>\n<blockquote>\n<p><strong>signal ·</strong> 真正被这条新闻定价的不是 3.7 个百分点的提升，而是同一个模型在攻与防两侧同时变强后，监管该按哪一侧来管它。</p>\n</blockquote>\n<h2 id=\"-日本-sakana-ai-推出多智能体编排系统-fugu称-fugu-ultra-在基准上对标-fable-与-mythos\">❯ 日本 Sakana AI 推出多智能体编排系统 Fugu，称 Fugu Ultra 在基准上对标 Fable 与 Mythos</h2>\n<p><code>[编排系统]</code> 据 VentureBeat 报道，日本 AI 实验室 <strong>Sakana AI</strong> 发布多智能体编排系统 <strong>Fugu</strong>，主打「一个模型 API 背后挂一整套智能体」的调用方式，并称高配版 <strong>Fugu Ultra</strong> 在多项基准上与 <strong>Fable</strong>、<strong>Mythos</strong> 打平。这是这家以「进化式合并模型」起家的日本实验室，首次把编排能力作为对外产品的核心卖点。</p>\n<p><code>[单一接口]</code> Fugu 的设计思路是把多智能体的复杂度藏在单一接口背后：开发者只对一个模型 API 发请求，编排、分工、调度都在内部完成。Sakana AI 由<strong>前谷歌研究员</strong>创办，过去以模型融合与小模型方向的研究著称，这次直接对标头部闭源模型，是一次明显的产品定位上移。不过对标的说法目前只有官方基准背书：有第三方在实测中指出，Fugu Ultra 虽然在某些可视化编程任务上观感最好，但要逼近开源的 GLM 5.2 水准，<strong>成本高出约 17 倍</strong>——纸面对标和单位成本之间，仍有一道没填平的缝。</p>\n<p><code>[怎么验货]</code> 对在选型的工程团队来说，Fugu 这类「单 API 编排多智能体」的产品，真正要看的不是发布会上的基准条形图，而是同等任务下的<strong>端到端成本与延迟</strong>。当 Fugu Ultra 被指出要 <strong>17 倍成本</strong>才接近开源模型时，采购方接下来要算的是：编排带来的效果增量，值不值这道价差。</p>\n<blockquote>\n<p><strong>signal ·</strong> Fugu 把多智能体打包成一个 API 是好故事，但选型方最后掏钱买的是「每一分效果到底贵了多少倍」。</p>\n</blockquote>\n<h2 id=\"-智谱市值首破-1-万亿港元股价年内涨幅超-2000\">❯ 智谱市值首破 1 万亿港元，股价年内涨幅超 2000%</h2>\n<p><code>[市值里程碑]</code> 据交易所行情数据，<strong>智谱</strong>（Zhipu AI）市值首次突破 <strong>1 万亿港元</strong>，股价年内累计涨幅超过 <strong>2000%</strong>。这家以 GLM 系列大模型起家的中国 AI 公司，由此跻身港股市值最高的 AI 标的之一，也是国产大模型阵营里二级市场表现最猛的一家。</p>\n<p><code>[开源叙事兑现]</code> 智谱的暴涨踩在国产开源模型集体走强的节点上：其 GLM 系列近期在多个真实世界智能体基准上排进前列，市场把「开源不再落后头部闭源几个月」的预期，直接计入了估值。据公开行情测算，年内<strong>超 20 倍</strong>的涨幅已经不只是业绩驱动，更是资金对「中国能跑出一线开源大模型」这条主线的重定价——参照同处赛道的字节、阿里近期动作，资本对中国 AI 资产的<strong>风险偏好</strong>正在整体抬升。</p>\n<p><code>[谁在重排序]</code> 一家大模型公司在港股冲上<strong>万亿港元</strong>，最先被改写的是机构对中国 AI 资产的配置排序：过去被当作「政策与算力受限」折价处理的国产模型公司，正重新拿回成长股的估值模板。对一级市场投资人来说，智谱的二级表现也给同梯队公司提供了一个<strong>新的退出与定价锚</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 年内 20 倍涨幅真正测试的不是智谱的模型，而是资金愿意给「中国一线开源大模型」开出多高的估值上限。</p>\n</blockquote>\n<h2 id=\"-字节跳动灰市估值升破-6000-亿美元消息人士称短期内难有上市动力\">❯ 字节跳动灰市估值升破 6000 亿美元，消息人士称短期内难有上市动力</h2>\n<p><code>[灰市定价]</code> 据《日经亚洲》报道，<strong>字节跳动</strong>股权在灰色市场的成交估值已升破 <strong>6000 亿美元</strong>；多位消息人士称，只要业务还在为其中国和美国股东持续创造回报，公司短期内<strong>不太可能 IPO</strong>。这把字节稳稳推到全球估值最高的未上市科技公司行列。</p>\n<p><code>[不上市的逻辑]</code> <strong>6000 亿美元</strong>的灰市估值，是在没有公开发行、仅靠私下转让撮合出的价格，本身已隐含相当大的<strong>流动性折价</strong>空间。据该报道，增长仍在、老股东仍在获利，IPO 反而会带来披露与监管成本，因此动力不足。背景是字节横跨 TikTok、抖音与一系列 AI 产品，地缘层面又长期处在中美博弈的风口——任何一次公开上市，都要同时面对两边监管与估值口径。维持非上市状态，等于把定价权继续握在内部和灰市手里。</p>\n<p><code>[谁被迫等待]</code> 6000 亿美元这个数字最直接的压力，落在字节的<strong>早期员工和老股东</strong>身上：估值越高、IPO 越遥遥无期，他们的账面财富和真实流动性之间的缺口就越大。对二级市场和指数基金而言，全球最贵的科技资产之一长期游离在公开市场之外，也让一块巨大的 <strong>AI 敞口</strong>暂时无法被纳入配置。</p>\n<blockquote>\n<p><strong>signal ·</strong> 灰市把字节标到 6000 亿美元，但真正稀缺的不是估值，而是让老股东把账面数字变现的那扇门。</p>\n</blockquote>\n<h2 id=\"-sk-海力士市值反超三星登顶韩国第一全天涨-56-至约-14-万亿美元\">❯ SK 海力士市值反超三星登顶韩国第一，全天涨 5.6% 至约 1.4 万亿美元</h2>\n<p><code>[登顶韩股]</code> 据《华尔街日报》报道，<strong>SK 海力士</strong>收盘上涨 <strong>5.6%</strong>，市值升至约 <strong>1.4 万亿美元</strong>，首次反超三星电子，成为韩国市值最高的公司；同期韩国综合股价指数（Kospi）年内累计上涨 <strong>117%</strong>。半导体存储龙头的位次，被高带宽内存的需求彻底改写。</p>\n<p><code>[HBM 改写座次]</code> SK 海力士能挤下长期占据榜首的三星电子，核心推力是 AI 数据中心对<strong>高带宽内存 HBM</strong> 的争抢——它是英伟达高端 AI 芯片的关键配套，而 SK 海力士在这一品类上占据领先供货地位。据该报道，Kospi 年内涨 <strong>117%</strong>，背后是整个韩国半导体板块在近一年里被 AI 算力周期重新定价。目前三星虽然体量更大、业务更全，但在最赚钱的 HBM 环节落了一个身位，市值因此被反超，成为 AI 算力需求向上游存储传导的一个标志性时刻。</p>\n<p><code>[谁要重看亚洲]</code> 一家存储厂商靠 HBM 登顶韩国第一，最先要重新评估的是全球资金对<strong>亚洲半导体</strong>的配置：过去三星是默认的韩国科技敞口，如今 SK 海力士用 AI 内存把这个锚换了位置。对配置 AI 产业链的投资者而言，算力故事的受益者不再只停在芯片设计与代工，已经实实在在<strong>传导到了内存这一层</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 三星被反超的不是规模，而是这一轮 AI 周期里最贵的那块拼图——高带宽内存的定价权。</p>\n</blockquote>\n<h2 id=\"-阿里巴巴发布视频生成模型-happyhorse-11\">❯ 阿里巴巴发布视频生成模型 HappyHorse 1.1</h2>\n<p><code>[版本更新]</code> <strong>阿里巴巴</strong>发布视频生成模型 <strong>HappyHorse 1.1</strong>，对其视频生成能力做了一轮迭代升级。这是阿里在多模态生成方向上的又一次版本推进，延续了国内大厂在文生视频、图生视频赛道密集发版的节奏。</p>\n<p><code>[大厂卡位]</code> HappyHorse 1.1 落在国产视频生成模型集中迭代的窗口期：过去一年里，从字节到快手再到阿里，头部厂商把视频生成当作多模态能力的<strong>主战场</strong>之一，版本号更新越来越快。阿里这次以小版本号迭代的方式发布，更像是对生成质量、时长或可控性的常规打磨，而非一次架构级跳变。对开发者而言，关键不在「又出了一版」，而在这版在<strong>分辨率、运动连贯性和推理成本</strong>上具体动了哪些。</p>\n<p><code>[谁来验收]</code> 视频生成模型的小版本迭代，最终要由<strong>内容创作者和应用开发者</strong>来验收：他们关心的是同样的提示词下，HappyHorse 1.1 出片的<strong>可用率</strong>有没有实质提升，渲染一条片子的时长和成本有没有下来。在大厂普遍以高频发版抢占心智的当下，留给单个版本号证明自己的窗口正在变短。</p>\n<blockquote>\n<p><strong>signal ·</strong> 文生视频进入小步快跑阶段，决定去留的不再是发版频率，而是每一版能把可用率往上抬几个点。</p>\n</blockquote>\n<h2 id=\"-英伟达发布机器人安全系统-halos推进具身智能落地\">❯ 英伟达发布机器人安全系统 Halos，推进具身智能落地</h2>\n<p><code>[安全系统]</code> <strong>英伟达</strong>发布机器人安全系统 <strong>Halos</strong>，把安全框架延伸到具身智能（Physical AI）场景，目标是为机器人从实验室走向真实物理环境提供一套可落地的安全底座。这是英伟达把 AI 安全议题从数据中心向物理世界外推的一步。</p>\n<p><code>[从软件到物理]</code> Halos 的指向很明确：当 AI 不再只是屏幕里的对话，而要驱动会移动、会施力的机器人时，安全的内涵就从「内容合规」变成「<strong>物理可控</strong>」——避免碰撞、误操作和失控。过去一年里，英伟达把 <strong>Physical AI</strong> 当作继生成式 AI 之后的主推叙事，先后发布仿真平台 <strong>Omniverse</strong>、机器人基础模型与这次的 Halos 安全系统，搭起一条完整的具身智能工具链。对机器人厂商来说，安全合规往往是量产部署前最难啃、又绕不开的一关，平台方把它标准化，等于降低了下游的落地门槛。</p>\n<p><code>[谁先受益]</code> 把安全做成可复用的系统，最先松一口气的是<strong>机器人本体厂商和工厂集成商</strong>：他们不必从零搭一套安全验证体系，而能直接接入平台方的框架。对监管和保险方而言，一套来自头部平台的标准化安全系统，也给「机器人进入人类工作空间」这件事提供了一个<strong>可对话的基准</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 具身智能能不能进工厂和家庭，卡点往往不在模型多聪明，而在安全这道关谁来兜底、按谁的标准兜。</p>\n</blockquote>\n<h2 id=\"-腾讯在微信内测试-ai-助手小微由-welm-与-deepseek-模型驱动\">❯ 腾讯在微信内测试 AI 助手「小微」，由 WeLM 与 DeepSeek 模型驱动</h2>\n<p><code>[微信内测]</code> 据彭博报道，<strong>腾讯</strong>开始在中国版微信内测试新的 AI 助手<strong>「小微」</strong>，底层由腾讯自研的 <strong>WeLM</strong> 与 <strong>DeepSeek</strong> 模型共同驱动，是其追赶 AI 的最新动作。把 AI 助手直接塞进微信这个国民级入口，意味腾讯选择在自己最大的流量场里打这一仗。</p>\n<p><code>[流量场的优势]</code> 「小微」最大的筹码不是模型本身，而是它所在的位置——微信坐拥<strong>十亿级月活</strong>，任何一个被嵌进对话框的 AI 助手，天然拥有别家产品砸钱也买不到的分发。腾讯采用自研 WeLM 加第三方 DeepSeek 模型混搭的路线，既保留对核心能力的掌控，又借开源强模型补齐短板，是务实的「<strong>自研＋外援</strong>」组合。背景是腾讯在大模型竞赛中起步不算最快，这次把战场拉回自己最熟悉的社交场，是用渠道优势对冲模型上的相对落后。</p>\n<p><code>[谁被改写预期]</code> 一个深度内嵌微信的 AI 助手，最先要重新掂量处境的是<strong>独立 AI 应用</strong>：当国民级 App 自带一个免下载、免注册的助手入口，第三方产品的获客成本和逻辑都被改写，接下来要盯的是小微被放在几级入口、对话框用户的实际<strong>转化率</strong>有多高。对 DeepSeek 而言，被腾讯选作底层模型之一，则是一次极具分量的渠道背书。</p>\n<blockquote>\n<p><strong>signal ·</strong> 腾讯这一仗的胜负手不在模型排行榜，而在十亿微信用户里有多少人愿意把对话框换成 AI 入口。</p>\n</blockquote>\n<h2 id=\"-openai-据称本周四一口气发-gpt-5656-pro-与双向语音模型-bidi-1\">❯ OpenAI 据称本周四一口气发 GPT-5.6、5.6 Pro 与双向语音模型 Bidi 1</h2>\n<p><code>[发布传闻]</code> 多个泄露账号称，OpenAI 计划在<strong>本周四</strong>集中发布一批新模型，包括 <strong>GPT-5.6</strong>、<strong>GPT-5.6 Pro</strong> 以及一款代号 <strong>Bidi 1</strong> 的双向语音模型。此为未证实传闻，仍以官方发布为准。其中语音模型据称会在设置里新增一档，对应入口的语音气泡也会从蓝色换成黄色。</p>\n<p><code>[节奏与卖点]</code> 按流出的说法，这批更新的看点不在「最强」，而在「<strong>最好用</strong>」：有账号称 GPT-5.6 在智能上不一定超过更高端的型号，但日常体验会明显更顺手；双向语音模型的早期测试则被形容为「两年前就盼着的样子」。需要强调的是，这些目前都来自<strong>泄露层单方信源</strong>，型号名、发布时间到能力描述均未获 OpenAI 官方确认，存在跳票或调整的可能。</p>\n<p><code>[怎么对待传闻]</code> 对开发者和产品团队而言，这类未证实的发布传闻<strong>只适合用来排期、不适合用来下注</strong>：真正值得等的是周四是否如期落地，以及双向语音是否如传言所说在延迟和自然度上有质变。在官方放出之前，型号清单、价格档位和能力边界都该先打上一个问号，别急着写进路线图。</p>\n<blockquote>\n<p><strong>signal ·</strong> 周四会不会兑现是一回事，更该盯的是 Bidi 1 这类双向语音能否把「能用」做成「想一直用」。</p>\n</blockquote>\n<h2 id=\"-anthropic-今日将-fable-5-移出订阅外界传-sonnet-5-已进入内测\">❯ Anthropic 今日将 Fable 5 移出订阅，外界传 Sonnet 5 已进入内测</h2>\n<p><code>[订阅调整]</code> 有观察账号称，<strong>Anthropic</strong> 今日起把 <strong>Fable 5</strong> 移出订阅档位，同时社区盛传 <strong>Sonnet 5</strong> 已进入内测。前者是被反复提及的订阅变动，后者仍属未证实传闻，均待官方说明为准。订阅用户最关心的，是 Fable 5 退出后会拿什么来补位。</p>\n<p><code>[补位猜想]</code> 围绕这次调整，社区的主要猜测是 Anthropic 会用即将到来的 <strong>Sonnet 5</strong> 作为补偿——历史上 Sonnet 档在发布初期曾多次在编码、速度和性价比上<strong>压过更早的 Opus 版本</strong>，因此「降一档却更划算」并非没有先例。但截至目前，Anthropic 对 Fable 5 的订阅去向和 Sonnet 5 的时间表都未给出公开说明，相关讨论里也夹杂着对沟通不足的不满。在官方表态之前，这更像是一次<strong>用户情绪的集中释放</strong>，而非可确认的产品路线。</p>\n<p><code>[谁在等回应]</code> Fable 5 退出订阅，最先要重新规划的是依赖它的<strong>付费用户和套壳应用方</strong>：他们要么等 Sonnet 5 顶上，要么临时切到其他档位甚至别家模型。对 Anthropic 而言，一次缺乏说明的订阅调整本身就是<strong>信任成本</strong>，接下来要看它用怎样的发布节奏把预期接住。</p>\n<blockquote>\n<p><strong>signal ·</strong> 移出一个模型不难，难的是 Anthropic 能否在用户切走之前，把 Sonnet 5 这块补位准时摆上来。</p>\n</blockquote>\n<h2 id=\"-苹果工业设计团队将由-john-ternus-接手部门十年来在高层渐失话语权\">❯ 苹果工业设计团队将由 John Ternus 接手，部门十年来在高层渐失话语权</h2>\n<p><code>[人事变动]</code> 据彭博社马克·古尔曼报道，<strong>苹果</strong>硬件工程主管 <strong>John Ternus</strong> 正准备把自己的印记打在工业设计团队上；消息称，这支曾定义苹果美学的部门，在过去 <strong>10 年里</strong>逐渐失去了在高层决策桌上的一席之地。设计团队的归属与话语权，正被重新安排。</p>\n<p><code>[工程主导]</code> 这条人事线索的分量，在于它折射出苹果内部权力结构的迁移：此前在<strong>乔纳森·艾维</strong>时代，工业设计一度是产品定义的源头；随着艾维 <strong>2019 年</strong>出走，设计团队的层级一路下沉，如今要并入由硬件工程主管 <strong>Ternus</strong> 主导的体系。这把苹果的产品决策重心，进一步从「设计先行」推向「工程先行」。在 AI 功能成为新卖点、硬件创新趋于平缓的当下，这种内部权重的转移并非孤立事件。</p>\n<p><code>[谁要重读苹果]</code> 设计团队改由工程主管节制，最先要重新判断的是长期跟踪苹果的<strong>供应链与产品观察者</strong>：未来几代设备的形态语言，可能更多由工程与量产可行性、而非纯粹美学来定调。对消费者而言，这未必立刻可感，却会缓慢改变苹果产品「<strong>先好看还是先好用</strong>」的优先级。</p>\n<blockquote>\n<p><strong>signal ·</strong> Ternus 接手工业设计，真正被改写的是苹果做产品时「设计与工程谁说了算」的那条隐形排序。</p>\n</blockquote>",
  "2026-06-18": "<div class=\"meta\"><span>2026-06-18</span><span class=\"sep\">·</span><span class=\"tag\">#模型安全</span><span class=\"sep\">·</span><span class=\"tag\">#国产开源</span><span class=\"sep\">·</span><span class=\"tag\">#港股IPO</span><span class=\"sep\">·</span><span class=\"tag\">#政务AI</span><span class=\"sep\">·</span><span class=\"st\">status: parsed</span></div><figure class=\"cover-slot\"><img src=\"/covers/2026-06-18.jpg\" alt=\"特朗普政府要求Anthropic证明Fable 5护栏不可绕过，方可重新上线 封面图\" loading=\"eager\" onload=\"this.closest('.cover-slot').classList.add('has-cover')\" onerror=\"this.closest('.cover-slot').classList.add('empty'); this.remove()\"><figcaption><span class=\"cover-k\">cover slot</span><span>上传封面图到 <code>public/covers/2026-06-18.jpg</code></span></figcaption></figure><h2 class=\"lead-title\">❯ 特朗普政府要求Anthropic证明Fable 5护栏不可绕过，方可重新上线</h2><p><code>[最强模型被关]</code> 据《连线》杂志报道，特朗普政府官员向 Anthropic 提出硬性条件：若想重新上线 Fable 5 模型，<strong>必须确保其安全护栏无法被绕过</strong>。但多位专家直言，这一要求在技术上<strong>几乎不可能实现</strong>——任何足够强大的模型都存在被越狱的路径。Fable 5 于 6 月 9 日发布，仅三天后即被政府强制关停，直接诱因是一家外部公司<strong>成功越狱了 Anthropic 最受限的内部模型 Mythos</strong>。</p>\n<p><code>[护栏悖论]</code> Fable 5 被 Anthropic 称为”全球最强 AI 模型”，其推理能力远超当前 Claude Opus 4.6。问题出在 Anthropic 内部最受限的 Mythos 模型——该模型从未公开发布，仅限内部使用，却被外部团队成功攻破。此事引发<strong>国家安全层面警觉</strong>后，政府直接叫停 Fable 5 的对外服务。目前 Anthropic 最新公开模型仍停留在 Claude Opus 4.6、Sonnet 4.6 与 Haiku 4.5 这一代，据彭博电视台报道，公司已切断对旗下最强模型的外部访问，Fable 5 何时重返市场尚无时间表。</p>\n<p><code>[安全与能力]</code> 此次事件将 AI 安全领域一个长期悬置的问题推到台前：<strong>护栏与能力是否存在根本性的此消彼长</strong>？模型越强，可被滥用的维度越多，绝对的不可绕过性在技术理论上难以成立。对 AI 开发者而言，Fable 5 的遭遇等于一个信号——最强模型的发布节奏可能不再是企业自主决策，而需要<strong>与政府达成前置安全协议</strong>。对 OpenAI 和 Google 来说，它们同样在推进前沿模型，此次监管先例将<strong>直接塑造后续产品的合规路径</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 护栏不可绕过是政治指令，不是工程目标——二者之间的矛盾决定了 Fable 5 短期内重返市场的概率很低。</p>\n</blockquote>\n<h2 id=\"-美国暂缓将deepseek长鑫存储等百余家中企列入实体清单创十年来最长空窗\">❯ 美国暂缓将DeepSeek、长鑫存储等百余家中企列入实体清单，创十年来最长空窗</h2>\n<p><code>[十年最长空窗]</code> 据路透社独家报道，美国政府已暂缓将中国 AI 公司 DeepSeek、存储芯片龙头<strong>长鑫存储及逾 100 家被认定存在国家安全风险的中国企业</strong>列入商务部实体清单。这批企业早在去年即已通过跨部门委员会审批，但正式公布<strong>至今被搁置</strong>。自 2025 年 10 月以来，美国实体清单未新增任何条目，<strong>创下逾十年来的最长更新间隔</strong>。</p>\n<p><code>[贸易优先管制]</code> 据知情人士透露，自 2025 年底以来，美国商务部工业与安全局负责人凯斯勒一直倾向<strong>避免新增对华制裁</strong>，以免加剧中美关系紧张。目前至少已有<strong>75 家涉及先进半导体制造、半导体设备和 AI 模型开发的中国实体</strong>完成跨部门审批、具备列入条件，但始终未正式公告。此外，数十家因向中国高校销售受限英伟达芯片而被认定存在风险的企业，以及向俄罗斯提供无人机的中国企业，也在拟制裁之列却一并被搁置。DeepSeek 今年初以低成本模型震动硅谷，随后被美国国务院指控支持中国军方项目，Anthropic 和 OpenAI 也分别指控其非法提取模型能力。</p>\n<p><code>[工具性重定义]</code> 美国智库战略与国际问题研究中心研究员勒克指出，实体清单像”打地鼠”游戏——<strong>长期不更新会导致美国技术持续流向潜在对手</strong>。前商务部官员库兰德则认为，这一空窗期反映<strong>贸易政策已凌驾于国家安全工具之上</strong>。对中国 AI 和半导体企业而言，这段窗口期客观上降低了短期供应链压力；但一旦中美谈判出现变数，这份已审批完毕的”待发布名单”随时可能落地，不确定性并未消除。</p>\n<blockquote>\n<p><strong>signal ·</strong> 清单不是被取消了，而是被当成了筹码——暂停是策略性的，不是战略转向。</p>\n</blockquote>\n<h2 id=\"-前阿里千问负责人林俊旸创立ai实验室天使轮估值达20亿美元\">❯ 前阿里千问负责人林俊旸创立AI实验室，天使轮估值达20亿美元</h2>\n<p><code>[中国最贵天使]</code> 据 The Information 报道，前阿里巴巴通义千问技术负责人<strong>林俊旸已创立新 AI 实验室</strong>，完成首轮数亿美元融资，据国内媒体消息，投后估值约 <strong>20 亿美元</strong>。本轮由<strong>高榕资本与红杉中国联合领投，各出资 1 亿美元</strong>，腾讯以 2000 万美元战略跟投。这一估值<strong>刷新国内 AI 初创天使轮纪录</strong>，且团队已着手筹备新一轮融资。</p>\n<p><code>[千问灵魂出走]</code> 林俊旸 1993 年出生，毕业于北京大学，曾是阿里巴巴最年轻的 P10 级技术负责人，主导了千问系列大模型从 0 到 1 的研发与开源全过程。在其领导下，Qwen 系列累计下载量于 2026 年初突破 10 亿。今年 3 月，林俊旸在社交媒体宣布离职，同期<strong>千问团队多名核心骨干相继出走</strong>，引发外界对阿里是否尊重顶级 AI 人才的广泛讨论。据工商信息，林俊旸已在上海注册多家实体，创业方向聚焦<strong>世界模型与具身智能</strong>，避开了大语言模型这一拥挤赛道。</p>\n<p><code>[人才定价重构]</code> 20 亿美元的天使轮估值，表明资本市场对<strong>中国 AI 顶级人才的定价体系已全面重构</strong>——不再是”先做产品再拿估值”，而是”先为人才定价，再等产品落地”。腾讯以 2000 万美元获得跟投席位，延续了其在月之暗面、MiniMax、智谱和 DeepSeek 的全线押注策略。对阿里而言，继杨红霞、周畅之后再次流失千问核心人物，<strong>人才储备压力持续累积</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 天使轮 20 亿——资本买的不是公司，是林俊旸这个人。</p>\n</blockquote>\n<h2 id=\"-智谱开源glm-52code-arena全球第一1m上下文mit协议\">❯ 智谱开源GLM-5.2，Code Arena全球第一，1M上下文+MIT协议</h2>\n<p><code>[登顶代码竞技]</code> 智谱 AI 于 6 月 17 日上线并开源 GLM-5.2 模型。在全球百万用户参与盲测的前端开发评估系统 <strong>Code Arena 上，GLM-5.2 取得全球可用模型第一</strong>的表现。据智谱官方介绍，GLM-5.2 专为<strong>长程任务能力</strong>而生——不再是即时问答，而是能像软件工程师一样<strong>连续工作数小时，自主跑完从开发到上线的完整工程</strong>。</p>\n<p><code>[国产算力适配]</code> 自 GLM-4.5 代码基座以来，智谱几乎投入全部力量攻关编程能力。GLM-5.2 在此基础上实现 Solid 1M 无损上下文，在多个长程任务基准上表现介于 Claude Opus 4.7 与 4.8 之间，是排名最高的开源模型。据智谱公布的数据，在 FrontierSWE 评测上仅比 Opus 4.8 低 1%。模型采用 <strong>MIT 开源协议</strong>，无地域限制，可自由下载、部署与商用。vLLM、SGLang、transformers 等主流推理框架已支持，并在 Day 0 完成对华为昇腾、平头哥、摩尔线程、寒武纪、昆仑芯、海光、壁仞等多个<strong>国产算力平台的推理适配</strong>。智谱预计下半年昇腾 950 超节点上市后，将成为 GLM-5.2 的强劲算力底座。</p>\n<p><code>[工程交付引擎]</code> GLM-5.2 的核心变量在于将 AI 从”代码补全工具”推向”工程交付引擎”。在实际体验中，GLM-5.2 曾累计处理 88 万 tokens，几乎用满 1M 上下文窗口，完成了一个覆盖 Web、移动端与小程序的多端应用交付——这在过去需要一支团队协作数周。对开发者而言，工作方式将从”<strong>AI 辅助编码</strong>”转向”<strong>AI 自主执行 + 人工审核</strong>”；对智谱而言，以 MIT 协议开源、支持国产算力的策略，等于用开放生态对抗闭源巨头的算力壁垒。</p>\n<blockquote>\n<p><strong>signal ·</strong> 1M 上下文 + MIT 协议 + 国产算力 = 中国开源模型迄今为止最具野心的工程交付宣言。</p>\n</blockquote>\n<h2 id=\"-小红书拟赴港ipo估值目标超700亿美元已聘高盛中金承销\">❯ 小红书拟赴港IPO，估值目标超700亿美元，已聘高盛中金承销</h2>\n<p><code>[超级IPO浮出]</code> 据《华尔街日报》报道，中国社交平台小红书正<strong>瞄准香港上市，最早今年底挂牌</strong>，目标估值超过 <strong>700 亿美元</strong>。此前在私募二级市场交易中，小红书估值从 2024 年的约 170 亿美元攀升至 2025 年底的<strong>逾 500 亿美元</strong>。据路透社消息，小红书已聘请<strong>高盛与中金公司</strong>担任承销商，计划于 6 月底前秘密提交上市申请。</p>\n<p><code>[四年翻四倍]</code> 小红书由毛文超和瞿芳于 2013 年在上海创立，已从生活分享社区演化为”内容+电商”的双轮平台。截至 2025 年，月活跃用户超过 4 亿，日活跃用户超 1.7 亿，全年营收约 420 亿元人民币，同比增长 40%。据知情人士预计，小红书 <strong>2026 年利润有望达到 30 亿美元</strong>。投资者阵容涵盖腾讯、阿里巴巴、红杉中国、高瓴资本、金沙江创投等头部机构。公司曾于 2021 年尝试赴美上市，后因<strong>监管环境变化搁置</strong>。今年香港 IPO 市场持续回暖，据彭博行业研究预计，全年募资额将突破 430 亿美元，创六年新高。</p>\n<p><code>[定价纪律考验]</code> 小红书若以 700 亿美元估值上市，将成为近年港股最大规模的科技股 IPO。但香港市场对科技股的定价纪律正在加强——近期上市的 AI 公司估值均面临压力测试。对早期投资者而言，<strong>从 170 亿到 700 亿美元的估值跃迁提供了丰厚退出空间</strong>，但最终发行价能否撑住这一水平，取决于监管审批节奏与届时的市场情绪。对抖音和快手而言，小红书上市后将拥有独立融资渠道，<strong>社交电商赛道的竞争格局将被重新定价</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 4 亿 MAU + 30 亿美元预期利润——小红书的 IPO 故事不缺基本面，定价纪律才是真正考验。</p>\n</blockquote>\n<h2 id=\"-库克称苹果涨价不可避免第二代iphone-air拟2027年春发布\">❯ 库克称苹果涨价”不可避免”，第二代iPhone Air拟2027年春发布</h2>\n<p><code>[芯片成本压顶]</code> 苹果 CEO 蒂姆·库克在《华尔街日报》专访中明确表态：<strong>苹果产品涨价已”不可避免”</strong>，以抵消持续飙升的<strong>内存和存储芯片成本</strong>。库克直言”这种情况已变得不可持续”，但没有透露具体涨幅和时间表。据《华尔街日报》此前测算，若成本压力完全传导，<strong>iPhone 18 Pro 起售价可能达 1299 美元</strong>，较当前旗舰再上一个台阶。</p>\n<p><code>[存储涨价潮]</code> 苹果的定价压力来自上游芯片市场的结构性紧张。自 2025 年以来，AI 服务器需求爆发挤占了存储芯片产能，DRAM 和 NAND 闪存价格连续多季度上涨。苹果自研芯片虽在逻辑计算端控制力强，但<strong>存储和内存仍依赖三星、SK 海力士、美光等外部供应商</strong>，成本传导能力有限。库克此次公开定调后，iPhone 18 系列将成为<strong>首轮定价分水岭</strong>——这将是苹果连续第三年在旗舰机型上提价。与此同时，据彭博社记者 Mark Gurman 披露，苹果正在测试<strong>第二代 iPhone Air</strong>，计划 2027 年春季发布，新机型将增加<strong>第二颗后置超广角摄像头</strong>并显著改善电池续航。</p>\n<p><code>[双线策略]</code> 一边旗舰涨价保毛利率，一边在中端产品线上持续加料——苹果的应对策略是<strong>拉大产品价格带宽度，同时维持全系竞争力</strong>。对消费者而言，购买决策将更明显地分化为”要最新技术就接受更高价格”和”要性价比就等 Air 产品线迭代”。对安卓阵营的对手而言，iPhone 涨价客观上为<strong>三星、小米等厂商留出高端定价空间</strong>，但也等于苹果在 1000 美元以上价格带的统治力将进一步坐实。</p>\n<blockquote>\n<p><strong>signal ·</strong> 涨价保利润 + Air 线加料保份额——苹果在成本飓风中打的是两道不相交的算盘。</p>\n</blockquote>\n<h2 id=\"-腾讯workbuddy入职广东政务系统全国首个省级智能中枢试运行\">❯ 腾讯WorkBuddy入职广东政务系统，全国首个省级智能中枢试运行</h2>\n<p><code>[AI入职政府]</code> 6 月 16 日，全国首个省级政务智能中枢平台<strong>”湾擎”在广州上线试运行</strong>，腾讯自研 AI 办公智能体 <strong>WorkBuddy 作为核心组件同步预发布</strong>，即将面向广东全省公务员开放使用。广东由此率先迈入”<strong>人手一个 AI 助手</strong>”的政务办公新阶段。据腾讯官方介绍，WorkBuddy 自今年 3 月上线以来，已成为国内日活跃用户最多的 AI 智能体办公工具。</p>\n<p><code>[六大政务场景]</code> 湾擎版 WorkBuddy 覆盖政务办公六大高频场景：<strong>公文辅助起草</strong>、材料合规校核、<strong>政策精准检索</strong>、业务智能咨询、跨部门流程协同和任务智能调度。区别于传统问答式工具，WorkBuddy 能自主拆解任务、调度工具，直接交付可用成果，如公文初稿或合规审查报告。安全方面，依托沙箱隔离技术实现<strong>数据不出域</strong>，已于今年 4 月通过中国信通院可信 AI 智能体能力评估，支持国产芯片与本地化私有部署。目前”湾擎”中枢已归集 100 余个政务场景，适配十数款主流大模型。</p>\n<p><code>[从试点到基建]</code> 这是 AI 智能体首次以省级规模进入政府核心办公流程。不同于过往的碎片化试点，“湾擎”中枢将广东政务 AI 从各搞各的整合为<strong>集约化运营</strong>，首批 8 个地市已获工场授牌。对腾讯而言，政务场景落地等于为 WorkBuddy 拿下了<strong>高壁垒、高复用的标杆客户</strong>——一旦广东模式跑通，全国其他省份的复制成本将大幅降低。对中国 AI 产业而言，这是”人工智能+“国家战略在政务领域迄今最完整的落地样本。</p>\n<blockquote>\n<p><strong>signal ·</strong> 从聊天机器人到交付公文的数字员工——政务 AI 的竞赛起跑线被广东画好了。</p>\n</blockquote>\n<h2 id=\"-小米mimo-claw正式版发布支持千次连续工具调用免费时长增至4小时\">❯ 小米MiMo Claw正式版发布：支持千次连续工具调用，免费时长增至4小时</h2>\n<p><code>[千次工具调用]</code> 小米于 6 月 17 日发布 MiMo Claw 正式版，核心升级是<strong>支持单次任务中连续调用工具超过 1000 次</strong>，大幅提升 AI 智能体在复杂工程中的自主执行能力。同时，<strong>免费使用时长增至每日 4 小时</strong>，对个人开发者和轻度用户构成实质吸引力。MiMo Claw 定位为 AI 编程智能体，集成 OpenClaw 实现代码即时预览，支持从需求描述到完整应用交付的端到端流程。</p>\n<p><code>[编程战加速]</code> MiMo Claw 正式版发布的时间点，恰好与智谱 GLM-5.2 强调长程任务、Anthropic 的 Claude Code 持续迭代形成共振。当前编程 Agent 赛道正从”谁家代码写得好”演进为”<strong>谁能跑完最长、最复杂的工程链路</strong>”。小米的差异化在于免费时长与工具调用次数——1000 次连续工具调用使模型可在一次任务中反复读写文件、执行命令、调试迭代，而不因调用上限中断。这一能力对于<strong>重构大型代码库、跨文件联调</strong>等场景具有工程意义。</p>\n<p><code>[隐性支点]</code> MiMo Claw 不是小米 AI 战略的全部，但它是<strong>最贴近开发者生态的产品</strong>。与小米汽车、手机等消费硬件相比，MiMo 系列承担的是”用免费工具培育开发者习惯、靠云服务和 API 变现”的经典平台策略。在 Anthropic Fable 5 被关停、国产编程 Agent 集体发力的背景下，<strong>工具调用次数和免费时长这类工程可用性指标</strong>，正在成为开发者选型的实际决策变量。</p>\n<blockquote>\n<p><strong>signal ·</strong> 1000 次工具调用不是炫技，是 Agent 从”会写”变成”能干活”的门槛线。</p>\n</blockquote>\n<h2 id=\"-spacex上市引爆韩国散户首日净买入近8亿美元创海外股票单日之最\">❯ SpaceX上市引爆韩国散户，首日净买入近8亿美元，创海外股票单日之最</h2>\n<p><code>[最强海外扫货]</code> 据韩国证券存管院 6 月 17 日公布的数据，SpaceX 于 <strong>6 月 12 日在纳斯达克上市首日</strong>，韩国散户投资者单日净买入<strong>7.96 亿美元（约合 1.215 万亿韩元）</strong> SpaceX 股票，创下韩国有史以来<strong>单日买入单只海外股票的最高纪录</strong>。在韩国逾 1400 万散户群体中，SpaceX 一举成为最受欢迎的海外持仓标的。</p>\n<p><code>[三重驱动力]</code> SpaceX 此次 IPO 为史上最大规模之一，据此前报道，承销商全额行使超额配售权后<strong>募资总额达 857 亿美元</strong>。韩国散户的狂热买入背后有三重驱动力：马斯克个人 IP 在韩国拥有极高号召力；SpaceX 在商业航天领域的垄断地位提供了稀缺性溢价；公司近期通过全股票方式以 600 亿美元估值收购 AI 编程工具 Cursor，为”<strong>火箭 + AI</strong>”的复合叙事增添了想象力。韩国是全球散户参与度最高的市场之一，2025 年韩国散户的海外股票交易量已超过本土市场。</p>\n<p><code>[散户FOMO升级]</code> 7.96 亿美元的单日净买入，相当于韩国散户过去五年平均每月海外股票净买入总额的约三分之一。这组数据既体现了 SpaceX 的品牌溢价能力，也暴露了<strong>全球散户对”下一个特斯拉”叙事的饥渴程度</strong>。对韩国监管机构而言，单一股票的高度集中持仓正在积累系统性风险——SpaceX 股价若出现大幅回调，韩国散户将首当其冲。对全球资本市场而言，SpaceX 上市首日的韩国数据，为后续 Starlink 分拆或 xAI 上市提供了<strong>需求端的最强参照</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 一天买近 8 亿美元——韩国散户用真金白银投票了他们对”马斯克宇宙”的定价。</p>\n</blockquote>",
  "2026-06-17": "<div class=\"meta\"><span>2026-06-17</span><span class=\"sep\">·</span><span class=\"tag\">#Anthropic</span><span class=\"sep\">·</span><span class=\"tag\">#SpaceX</span><span class=\"sep\">·</span><span class=\"tag\">#Cursor</span><span class=\"sep\">·</span><span class=\"tag\">#DeepSeek</span><span class=\"sep\">·</span><span class=\"st\">status: parsed</span></div><figure class=\"cover-slot\"><img src=\"/covers/2026-06-17.jpg\" alt=\"Anthropic叫停Claude Agent SDK按量计费，重度开发者获暂时喘息 封面图\" loading=\"eager\" onload=\"this.closest('.cover-slot').classList.add('has-cover')\" onerror=\"this.closest('.cover-slot').classList.add('empty'); this.remove()\"><figcaption><span class=\"cover-k\">cover slot</span><span>上传封面图到 <code>public/covers/2026-06-17.jpg</code></span></figcaption></figure><h2 class=\"lead-title\">❯ Anthropic叫停Claude Agent SDK按量计费，重度开发者获暂时喘息</h2><p><code>[计费回调]</code> 原定6月15日生效的定价变更被Anthropic在最后关头叫停。公司<strong>5月13日曾宣布</strong>将Claude Agent SDK、claude -p命令行及第三方集成用量从订阅池剥离，改用独立月度信用额度按API费率计费——实质大幅推高重度用户成本。本周一，Anthropic更新支持页面称”暂停上述变更”，<strong>“目前一切照旧”</strong>，正在优化方案。</p>\n<p><code>[开发者抵制]</code> 按原方案，Agent SDK用量将从Pro、Max、Team、Enterprise订阅中移出，转为独立月度额度，<strong>不跨用户共享、不滚动</strong>，耗尽后按标准API费率计费或直接停服。JetBrains IDE插件、GitHub Actions集成及大量第三方工具均依赖此通道。社区反弹激烈，Reddit讨论持续数日。同期<strong>Codex等竞品加速向开发者示好</strong>，外部竞争压力或推动了这次回调。</p>\n<p><code>[方向未变]</code> 暂停不等于取消——Anthropic的措辞是”正在更新方案”，更像是一次定价实验遇阻后的战术回调。对依赖Claude Agent SDK做自动化编程的团队而言，<strong>喘息窗口应用来评估替代方案和成本模型</strong>。无论方案如何调整，从打包订阅走向按量计费的方向不会逆转，差别只在于路径和节奏。</p>\n<blockquote>\n<p><strong>signal ·</strong> 定价权博弈——开发者用脚投票的能力，正在变成模型公司设计商业模式时必须计算的变量。</p>\n</blockquote>\n<h2 id=\"-spacex上市三日市值超亚马逊马斯克称2030年营收可达万亿美元\">❯ SpaceX上市三日市值超亚马逊，马斯克称2030年营收可达万亿美元</h2>\n<p><code>[三日超车]</code> SpaceX上市仅三个交易日就改写了美股排名。上周五IPO定价135美元，首日收涨<strong>19.6%至160.95美元</strong>；周二再涨<strong>4.83%至约213美元</strong>，市值达<strong>2.65万亿美元</strong>，正式超过亚马逊。当日盘中一度暴涨约12%，<strong>短暂超越微软的2.93万亿美元</strong>市值，成为美国第四大上市公司。</p>\n<p><code>[营收豪赌]</code> 马斯克周末在X平台发帖称SpaceX”<strong>或许能在2030年达到约1万亿美元营收</strong>”，2031年则”会惊讶于营收不足万亿”。对标IPO文件：SpaceX 2025年营收<strong>18.7亿美元</strong>，Starlink贡献32亿美元但亏损64亿美元。摩根士丹利预测2030年营收3300亿美元——马斯克的目标是投行最乐观估计的三倍。前特斯拉董事Steve Westly对CNBC警告：若马斯克<strong>三四个季度内达不到S-1指引，投资者”会很暴躁”</strong>。</p>\n<p><code>[稀缺溢价]</code> 上市仅发行约4.2%总股本（绿鞋后约4.9%），极低流通量放大了波动。首日散户净买入<strong>1.176亿美元，占全美零售买单56%</strong>。高波动叠加极小float的结构，使任何对Starlink现金流和火星叙事节奏的判断都建立在极薄的市场厚度上——<strong>定价容易，定价准很难</strong>。投资者须重新评估：这股的价格到底来自基本面还是供应稀缺？</p>\n<blockquote>\n<p><strong>signal ·</strong> 万亿美元营收是一个”讲故事”的数字——它不是预测，是马斯克为SpaceX定价锚定想象空间的方式。</p>\n</blockquote>\n<h2 id=\"-spacex以600亿美元全股票收购cursorai编程赛道最大交易落定\">❯ SpaceX以600亿美元全股票收购Cursor，AI编程赛道最大交易落定</h2>\n<p><code>[交易敲定]</code> SpaceX周二宣布正式签约以<strong>600亿美元全股票收购AI编程初创公司Cursor</strong>，交易预计<strong>2026年第三季度完成</strong>。Cursor将成为SpaceX全资子公司。据CNBC及SEC文件显示，若任一方退出，终止费为<strong>40亿至100亿美元</strong>。就在几天前，SpaceX刚完成史上最大IPO，募资超850亿美元。</p>\n<p><code>[截胡融资]</code> 今年4月，SpaceX已获得收购Cursor的权利——要么以600亿美元买下公司，要么支付100亿美元”合作费”。被SpaceX截胡前，Cursor正筹备由<strong>a16z、Thrive、英伟达</strong>领投的20亿美元融资轮，估值500亿美元。据TechCrunch报道，Cursor 2025年11月年化营收突破<strong>10亿美元</strong>，其Composer功能配合Claude Sonnet，在2025年初直接催生了”vibe coding”一词。马斯克今年早些时候已将xAI并入SpaceX。</p>\n<p><code>[竞速逻辑]</code> 这场收购是用IPO换来的股权弹药，在AI编程赛道做一次杠杆极高的下注。Cursor的开发者分发网络，加上SpaceX号称”百万H100等效”的Colossus超级计算机，目标是直接挑战<strong>Anthropic Claude Code和OpenAI Codex</strong>在开发者工具领域的统治地位。观察者需判断：<strong>合并后能否在产品层面兑现协同，而非互相消耗</strong>——这是此后最核心的变量。</p>\n<blockquote>\n<p><strong>signal ·</strong> SpaceX正用上市得来的资本势能，把AI军备竞赛直接拉到并购层面——不再是模型之间的竞争，而是资本效率的对决。</p>\n</blockquote>\n<h2 id=\"-苹果拟2027年推摄像头airpods同步发布折叠iphone周年纪念版\">❯ 苹果拟2027年推摄像头AirPods，同步发布折叠iPhone周年纪念版</h2>\n<p><code>[三箭齐发]</code> 据彭博社Mark Gurman报道，苹果计划在<strong>2027年底</strong>推出<strong>搭载摄像头的AirPods</strong>，与<strong>20周年纪念版Pro iPhone</strong>及<strong>第二代折叠屏iPhone</strong>同步发布。三款设备均配备摄像头并通过iPhone调用Siri视觉智能，实时理解用户所见场景。</p>\n<p><code>[AI穿戴首秀]</code> 摄像头版AirPods外观接近AirPods Pro 3，但耳机柄内嵌摄像头模组。原计划2026年发布，因<strong>苹果在AI和视觉模型上持续遇阻</strong>而推迟一年。三款设备目前正基于iOS 28测试，但时间表”仍有变动可能”。苹果同期还在推进智能眼镜和AI pendant——三条产品线的共同逻辑是：<strong>AI助手的入口不能只停留在手机屏幕里</strong>。</p>\n<p><code>[生态逻辑]</code> 苹果的打法不同于Meta的独立头显路线——所有穿戴设备都只是iPhone的传感外设，处理与推理留在手机端。好处是穿戴设备成本可控、续航可管，代价是离开iPhone就变砖。对开发者而言，2027年将催生一个<strong>新的Siri交互范式</strong>——从触控+语音升级为视觉+语音——第一波真正面向AI穿戴的应用场景将从这里长出。</p>\n<blockquote>\n<p><strong>signal ·</strong> 摄像头是AI的眼睛。苹果把摄像头塞进AirPods，本质是在为Siri装上一副能看世界的”眼镜”——不是AR眼镜，但路径更务实。</p>\n</blockquote>\n<h2 id=\"-deepseek完成首轮74亿美元融资估值超500亿梁文锋设lp结构锁死控制权\">❯ DeepSeek完成首轮74亿美元融资，估值超500亿，梁文锋设LP结构锁死控制权</h2>\n<p><code>[首轮即巨轮]</code> 据The Information报道，DeepSeek已完成首轮外部融资，<strong>募资超74亿美元，投后估值超500亿美元</strong>。这是中国AI领域迄今最大单笔融资之一。参与方包括腾讯、宁德时代、网易、京东、IDG资本、Monolith Capital及中国国家人工智能产业投资基金。梁文锋个人跟投约<strong>200亿元人民币</strong>。</p>\n<p><code>[控制权设计]</code> DeepSeek此前从未接受外部融资，梁文锋多次公开表态”不会被资本绑架”。本轮结构极其特殊：投资者资金注入<strong>梁文锋担任GP的有限合伙实体</strong>，而非直接投资DeepSeek。除国家AI产业基金外，所有投资者<strong>无投票权且受五年锁定期约束</strong>。据Moneycontrol报道，梁文锋借此在<strong>74亿美元融资规模和创始人绝对控制权</strong>之间找到了一条中国科技创业史上罕见的中间路径。</p>\n<p><code>[估值跳升]</code> 今年初DeepSeek估值约100亿美元，半年内跳至500亿以上，背后是V4模型在国产芯片（昇腾950PR）上的适配突破和开源生态的持续扩张。但锁死控制权也锁住了投资者的退出通道——LP结构下流动性严重受限，这轮融资更像一张与DeepSeek长期绑定的<strong>”信仰票”，而非常规的财务投资</strong>。投资者须重新判断：五年锁定期结束后，500亿美元的估值是高了还是低了？</p>\n<blockquote>\n<p><strong>signal ·</strong> 梁文锋用LP结构解了一道几乎所有创始人面对的方程：拿大钱，但不交权。代价是让投资人变成”只出钱、不说话的乘客”。</p>\n</blockquote>\n<h2 id=\"-支付宝二十年来最大改版阿宝ai智能体上场一万项服务对话即达\">❯ 支付宝二十年来最大改版：“阿宝”AI智能体上场，一万项服务对话即达</h2>\n<p><code>[底座重构]</code> 蚂蚁集团启动支付宝<strong>二十年来最大规模改版</strong>，将这款拥有超10亿用户的支付工具转型为以AI智能体为核心的对话平台。新版支付宝首页右滑即可唤出交互助手<strong>”阿宝”（Ah Bao）</strong>，用户通过文字或语音即可调用超过<strong>一万项日常服务</strong>——叫车、点咖啡、订外卖、买基金，全部由AI协调执行。目前仍为邀请制内测。</p>\n<p><code>[超级应用之争]</code> 据南华早报和彭博社报道，蚂蚁此举直指微信——后者也在测试AI智能体内测版。两大平台各坐拥超10亿用户，谁先把AI植入日常服务流，谁就掌握了下一代”超级应用”的定义权。更远处，<strong>字节跳动的豆包也在向购物导购延伸</strong>，阿里巴巴的千问则从电商佣金侧切入。四大巨头围绕”AI+超级应用”的消耗战已经打响，且短期内看不到任何一方会先踩刹车。</p>\n<p><code>[安全护栏]</code> 蚂蚁为阿宝设置了审慎的边界：金融交易需二次确认、敏感操作限制频次、对话记录可回溯。这与其说是技术限制，不如说是监管预判——让一个AI助手直接操作10亿人的钱包，任何一次失控都是不可接受的。能否在<strong>”足够好用”和”足够安全”之间找到平衡点</strong>，将决定阿宝是成为入口还是沦为摆设。</p>\n<blockquote>\n<p><strong>signal ·</strong> 当支付、出行、外卖、理财全部收敛到一个对话入口，超级应用的竞争从”谁装得下更多功能”变成了”谁能用一句话把事办了”。</p>\n</blockquote>\n<h2 id=\"-字节ai账本曝光豆包日收入不足百万seedance毛利70\">❯ 字节AI账本曝光：豆包日收入不足百万，Seedance毛利70%</h2>\n<p><code>[收入反差]</code> 豆包3.45亿月活、日均Token调用超120万亿——用户规模和算力消耗均断层领先，但<strong>C端日收入不足100万元</strong>。5月上线的三档付费订阅（68元/200元/500元月费）目前付费转化率极低，中国用户AI付费意愿约为美国的<strong>三分之一至四分之一</strong>。结果是豆包的用户增长越快，算力账单越厚，盈利缺口越大。</p>\n<p><code>[视频印钞机]</code> 与豆包订阅的拮据形成鲜明对比的是Seedance 2.0的财务表现。作为当前<strong>全球SOTA视频生成模型</strong>，Seedance 2.0采用差异化Token计费——纯生成模式46元/百万Token，生成15秒720P视频约需15元（一秒一元）。火山引擎披露其<strong>毛利率达70%</strong>，且面向企业用户公测刚刚开启。相比文本对话的”烧钱换规模”，视频生成的单位经济模型已率先跑通——这解释了字节2026年将世界模型列为首要命题的战略逻辑。</p>\n<p><code>[商业化分野]</code> 字节AI业务正划出两条截然不同的增长曲线：<strong>C端豆包是”规模换时间”，B端MaaS是”效率换利润”</strong>。火山引擎2025年MaaS收入占中国公有云市场份额49.2%，2026年目标直指百亿规模。衡量字节AI成败的核心指标已从”豆包有多少月活”转变为”<strong>Token工厂能不能养住整个AI部门</strong>”——账本不会说谎。</p>\n<blockquote>\n<p><strong>signal ·</strong> 豆包的规模优势不等于商业优势。Seedance才是字节AI账本上真正在赚钱的那一行——视频生成找到了文本对话还没找到的东西：正毛利。</p>\n</blockquote>\n<h2 id=\"-腾讯2000万美元入股林俊旸ai实验室天使轮估值即达20亿美元\">❯ 腾讯2000万美元入股林俊旸AI实验室，天使轮估值即达20亿美元</h2>\n<p><code>[明星创业者]</code> 据知情人士透露，腾讯出资<strong>2000万美元</strong>参与前阿里巴巴通义千问技术负责人林俊旸创立的AI实验室首轮融资。本轮由<strong>高榕资本和红杉中国各出资1亿美元联合领投</strong>，投后估值约<strong>20亿美元（136亿元人民币）</strong>，刷新国内AI初创公司天使轮估值纪录。团队已着手筹备新一轮募资。</p>\n<p><code>[千问缔造者]</code> 林俊旸1993年出生，北大毕业，曾是阿里最年轻的P10级技术负责人，主导了<strong>通义千问系列从0到1的研发与开源全流程</strong>，Qwen系列全球累计下载量2026年初突破10亿次。今年3月从阿里离职，创业方向聚焦<strong>世界模型与具身智能</strong>。腾讯此前已投资月之暗面、MiniMax、智谱AI，并正参与DeepSeek最新轮融资——据新浪科技报道，2000万美元虽小，但进到这个超高门槛的天使轮本身就是信号。</p>\n<p><code>[天使轮军备化]</code> 20亿美元的天使轮估值在三年前不可想象。这不是泡沫的证明，而是中国AI顶尖人才的<strong>定价体系已被彻底重置</strong>——一个缔造过全球头部开源模型的技术负责人，在创业第一天就被市场用20亿美元估值来锁定。对阿里而言，失去林俊旸的代价可能远大于腾讯投入的2000万美元本身。</p>\n<blockquote>\n<p><strong>signal ·</strong> 中国AI人才争夺已从薪资战升级为”天使轮估值战”——顶级研究员创业的第一个数字不再是年薪，而是十亿美元起跳的投后估值。</p>\n</blockquote>\n<h2 id=\"-硅基流动完成超20亿元b轮融资携程晶科金蝶等产业资本集体押注token工厂\">❯ 硅基流动完成超20亿元B轮融资，携程晶科金蝶等产业资本集体押注Token工厂</h2>\n<p><code>[全产业链站台]</code> 硅基流动宣布完成<strong>超20亿元人民币B轮融资</strong>，由<strong>携程战投、晶科能源、金蝶股份、联通新沃</strong>、盛奕资本（润泽集团）、壁仞战投、蔚来资本、商汤战投、巨人网络等产业资本与国资联合投资，华兴资本任独家财务顾问。公司集齐了从能源、芯片、算力到云服务、大模型、应用场景的全产业链投资者。</p>\n<p><code>[Token工厂]</code> 硅基流动以”Token工厂”定位切入AI基础设施——将裸算力通过自研推理引擎和异构调度系统转化为标准化Token输出。据公司披露，目前服务<strong>超1000万用户和1万家企业客户</strong>，日均Token调用量达数万亿，<strong>营收同比增长超10倍</strong>，海外市场月营收达数百万美元。据IDC数据，硅基流动是中国公有云MaaS市场份额前四中唯一一家创业公司。</p>\n<p><code>[算电协同样本]</code> 晶科能源的投资是这轮最值得注意的变量——光伏+储能龙头与AI推理平台的资本绑定，折射出一个正在成型的产业命题：<strong>AI竞争的下一程不是模型参数的战争</strong>，而是”电力-算力-模型-应用”全链路效率的战争。谁能把一度电变成更多可计费Token，谁就在AI基础设施层拿到了成本定价权。</p>\n<blockquote>\n<p><strong>signal ·</strong> Token工厂模式跑通了一个朴素的逻辑——AI时代卖水比淘金更稳。当所有人都在抢模型和用户时，硅基流动在抢”把算力变成钱”的效率。</p>\n</blockquote>",
  "2026-06-16": "<div class=\"meta\"><span>2026-06-16</span><span class=\"sep\">·</span><span class=\"tag\">#Anthropic</span><span class=\"sep\">·</span><span class=\"tag\">#SpaceX</span><span class=\"sep\">·</span><span class=\"tag\">#高通</span><span class=\"sep\">·</span><span class=\"tag\">#智谱</span><span class=\"sep\">·</span><span class=\"st\">status: parsed</span></div><figure class=\"cover-slot\"><img src=\"/covers/2026-06-16.jpg\" alt=\"美国商务部对 Anthropic 下达出口管制令，涉事模型面临全球下架 封面图\" loading=\"eager\" onload=\"this.closest('.cover-slot').classList.add('has-cover')\" onerror=\"this.closest('.cover-slot').classList.add('empty'); this.remove()\"><figcaption><span class=\"cover-k\">cover slot</span><span>上传封面图到 <code>public/covers/2026-06-16.jpg</code></span></figcaption></figure><h2 class=\"lead-title\">❯ 美国商务部对 Anthropic 下达出口管制令，涉事模型面临全球下架</h2><p><code>[紧急禁令]</code> 美国商务部工业与安全局（BIS）于 6 月 12 日下午签发出口管制令，以国家安全为由禁止 Anthropic 向任何外国国民开放其最高能力层级的 <strong>Claude Fable 5</strong> 与 <strong>Mythos 5</strong> 模型。据 Financial Times 援引知情人士报道，Anthropic 仅被给予 <strong>90 分钟</strong>合规时间，且在命令下达前未收到政府的详细关切说明。禁令导致两模型在全球范围被迫停用，受影响的不只是外国用户，甚至包括 Anthropic 自身持有外国国籍的员工。</p>\n<p><code>[争议溯源]</code> 事件的公开导火索是亚马逊研究人员在 Fable 5 中发现一个所谓越狱漏洞，亚马逊 CEO Andy Jassy 于 6 月 11 日向白宫表达担忧。但 Anthropic 辩称，这只是一个<strong>狭窄、非通用的轻微问题</strong>，同类能力在 OpenAI GPT-5.5 等竞品中同样存在，且 Fable 5 发布前已获商务部相关机构的安全测试批准。白宫官员则称”苦劝数小时无果后，出口管制已是不得已的最后手段”——双方对事前是否给出主动合作选项各执一词。</p>\n<p><code>[连锁影响]</code> 这场争议正值 Anthropic 于 6 月 1 日秘密提交美国 IPO 申请、又刚在 3 月被国防部列入供应链风险名单之际。Anthropic 已派高级技术团队赴华盛顿谈判，并将与特朗普政府举行正式会谈。对 AI 行业，此案开创了一个危险先例：<strong>政府可在不提供具体证据的情况下，直接切断已部署的商业模型</strong>——Adobe、NVIDIA 等公司已发起”Free Fable”公开信要求撤销禁令。</p>\n<blockquote>\n<p><strong>signal ·</strong> 当模型能力变成出口管制标的，AI 公司的最大风险就不再是技术竞争，而是与政府之间的信任机制。</p>\n</blockquote>\n<h2 id=\"-spacex-上市首日涨近-20ipo-总募资达-857-亿美元\">❯ SpaceX 上市首日涨近 20%，IPO 总募资达 857 亿美元</h2>\n<p><code>[史上最大IPO]</code> SpaceX 股票在纳斯达克上市首日收盘报 <strong>161 美元</strong>，较 135 美元发行价上涨约 <strong>19.6%</strong>，首日收盘市值约 <strong>2.1 万亿美元</strong>。据 CNBC 报道，承销商已行使超额配售权，IPO 总募资额从 6 月 11 日初始的 <strong>750 亿美元</strong>升至 <strong>857 亿美元</strong>，正式超过沙特阿美成为史上最大 IPO。认购需求超过 <strong>3500 亿美元</strong>，近三分之一机构未获配售，散户净买入量达英伟达的 3.5 倍。</p>\n<p><code>[万亿目标分歧]</code> 作为背景，SpaceX 2025 年营收 <strong>187 亿美元</strong>（星链贡献 61%），而马斯克在 X 上发文称公司”<strong>可能达到约 1 万亿美元</strong>”年收入（2030 年）。摩根士丹利和高盛对该目标的预测分别约为 3300 亿和 4700 亿美元，与马斯克的愿景存在数倍差距。首日大涨后，航天概念股表现分化——SpaceX 吸走了板块大部分资金，维珍银河跌 25%、Rocket Lab 跌 9%。</p>\n<p><code>[财富与市场效应]</code> 马斯克持有约 42% 股份，首日后持 SpaceX 股份价值约 <strong>7670 亿美元</strong>，使其成为全球首位万亿富豪。但结构影响更值得追踪：SpaceX 的上市为<strong>万亿级科技 IPO 打开了一扇门</strong>，后续 Anthropic、OpenAI 的上市节奏和估值预期都可能被此锚定。对投资者，下一个变量是 SpaceX 能否在 6 月 23 日被恒生港美科技指数纳入后的被动资金涌入。</p>\n<blockquote>\n<p><strong>signal ·</strong> 史上最大 IPO 的吸金效应重新定义了科技公司的上市天花板，也让”万亿市值”从口号变成了估值坐标。</p>\n</blockquote>\n<h2 id=\"-高通据称拟以-80-至-100-亿美元收购-ai-芯片公司-tenstorrent\">❯ 高通据称拟以 80 至 100 亿美元收购 AI 芯片公司 Tenstorrent</h2>\n<p><code>[十年最大并购]</code> 据 The Information 援引知情人士报道，Qualcomm 正在早期洽谈收购 AI 芯片设计公司 <strong>Tenstorrent</strong>，报价区间 <strong>80 亿至 100 亿美元</strong>。Tenstorrent 由芯片传奇架构师 <strong>Jim Keller</strong>（曾主导 AMD Zen、Apple A4/A5、Tesla HW 3.0 芯片设计）执掌，主打 RISC-V 开源指令集 AI 加速器，累计融资超 11.8 亿美元。去年底 Tenstorrent 曾以约 32 亿美元估值洽谈 8 亿美元融资，收购溢价达数倍之多。</p>\n<p><code>[RISC-V赌注]</code> 这是高通半年内第二笔 RISC-V 收购——2025 年 12 月已收购 Ventana Micro Systems。收购 Tenstorrent 将带来：<strong>RISC-V CPU IP</strong>（降低对 ARM 依赖）、AI 训练与推理加速器、数据中心产品线。同时 Intel 也在 5 月表达过收购兴趣，形成竞购格局。消息公布后高通股价跳涨超 4%，市场看好手机芯片巨头向数据中心 AI 的转型。</p>\n<p><code>[芯片竞争新格局]</code> 若交易达成，高通将直接与 NVIDIA 在数据中心 AI 芯片市场正面竞争，同时以 RISC-V 生态挑战 ARM 在移动和边缘计算的统治地位。对 AI 基础设施采购方，这代表算力供应链正在从”NVIDIA 一家独大”走向<strong>多元架构竞争</strong>——RISC-V 的开源性质和不受出口管制限制的特征，使其对中美两地的数据中心客户都有战略吸引力。</p>\n<blockquote>\n<p><strong>signal ·</strong> 高通不是在收购一家芯片公司，而是在买一个不受 ARM 和 x86 约束的算力未来。</p>\n</blockquote>\n<h2 id=\"-fox-以约-250-亿美元收购-roku流媒体市场迎来第三极\">❯ Fox 以约 250 亿美元收购 Roku，流媒体市场迎来第三极</h2>\n<p><code>[最大媒体收购]</code> Fox Corporation 于 6 月 15 日宣布以约 <strong>250 亿美元</strong>股权价值收购流媒体平台 Roku，据公司公告每股收购价 <strong>160 美元</strong>（含 96 美元现金加 Fox 股票），较前收盘溢价约 11.4%。交易后 Fox 股东持合并公司约 <strong>73%</strong>，Roku 股东持 <strong>27%</strong>，Roku CEO Anthony Wood 将留任并加入 Fox 董事会。Fox 已从摩根士丹利获得 120 亿美元过桥融资，交易预计 2027 年上半年完成。</p>\n<p><code>[内容+平台逻辑]</code> Fox 拥有 Fox News、Fox Sports 和免费流媒体 Tubi，但一直缺乏规模化分发平台——此前推出的 Fox One 应用始终无法与 YouTube、Netflix 竞争。Roku 拥有全球 <strong>超 1 亿流媒体家庭</strong>，在美国 CTV 市场按播放时长排名第一。合并后公司将成美国电视收视份额<strong>第三大玩家</strong>，仅次 YouTube 和 Netflix。年成本协同效应预计约 <strong>4 亿美元</strong>，核心是 Fox 内容 + Roku 用户数据与广告平台。</p>\n<p><code>[投资者质疑]</code> 市场反应冷淡：Fox 股价当日收跌超 <strong>15%</strong>，成标普 500 当日最差表现，投资者担心收购价过高、债务加重。Roku 仅微涨约 2%，部分投资者认为 11% 溢价偏低。这笔交易仍需通过反垄断审查，但分析认为<strong>垂直整合</strong>（内容方+分发平台）通过概率较高。对传统媒体集团，这笔交易将把流媒体竞争的门槛从内容投入升级为<strong>平台级资本的博弈</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 流媒体战争从烧钱做内容升级到了花百亿买平台，行业门槛正在从内容壁垒变为规模壁垒。</p>\n</blockquote>\n<h2 id=\"-摩根大通上调智谱至-1400-港元目标价股价飙升-33\">❯ 摩根大通上调智谱至 1400 港元目标价，股价飙升 33%</h2>\n<p><code>[定价权溢价]</code> 摩根大通在 6 月 15 日报告中维持智谱”增持”评级，将目标价大幅上调 <strong>47%</strong> 至 <strong>1400 港元</strong>，核心理由是<strong>定价权</strong>——智谱年内 API 价格翻倍但使用量仍增长，被视为”定价者行为”。智谱当日盘中一度涨 48%，收盘涨约 <strong>33%</strong>，市值突破 4500 亿港元。同期 MiniMax 仅涨 7%；摩根大通将其下调至”中性”，因 MiniMax 新模型上线一周即永久降价 50%，被解读为市场拒绝其技术溢价。</p>\n<p><code>[赛道分化]</code> 智谱 2026 年 1 月在港上市成为”全球大模型第一股”，2025 年营收 <strong>7.24 亿元</strong>（同比增 132%），已公告拟回 A 股科创板募资 150 亿元。其模式以 B 端 MaaS 本地化部署为主（占收入 84%），与 MiniMax 的 C 端出海路线形成鲜明对比。摩根大通判断中国 AI 行业已从”百模大战”进入<strong>淘汰赛</strong>，能从 200 多家缩至不足 10 家，决胜关键在于持续交付 SOTA 与维持定价权。</p>\n<p><code>[替代效应]</code> 特朗普政府对 Anthropic 的出口管制禁令意外成为催化剂——Fable 5 的全球停用让中国大模型厂商获得了”替代窗口”，美银同日首次覆盖智谱与 MiniMax 均给予买入评级。对 AI 投资者，这个信号比模型跑分更重要：资本正在用<strong>定价权而非基准测试得分</strong>来重新评估中国 AI 公司的真实壁垒。</p>\n<blockquote>\n<p><strong>signal ·</strong> 当一家公司敢在价格战中涨价且用户不走，它就拥有了整个赛道中最稀缺的东西——定价权。</p>\n</blockquote>\n<h2 id=\"-英伟达发行-250-亿美元公司债投资者认购达-850-亿\">❯ 英伟达发行 250 亿美元公司债，投资者认购达 850 亿</h2>\n<p><code>[创纪录发债]</code> 英伟达于 6 月 15 日完成 <strong>250 亿美元</strong>投资级公司债发行，初始目标约 200 亿美元，因需求旺盛追加。据公司公告这是英伟达自 2021 年以来首次发债，上一次规模仅 50 亿美元。投资者认购金额高达 <strong>850 亿美元</strong>，超额 3 倍以上，30 年期债券最终利差收窄至仅较美国国债溢价 <strong>65 个基点</strong>。本次发行涵盖 2 年至 30 年共 7 个期限，承销商为摩根大通、高盛、摩根士丹利。</p>\n<p><code>[为何还要借]</code> 据财报显示英伟达上一季度自由现金流达 <strong>486 亿美元</strong>，账面现金及投资 <strong>806 亿美元</strong>，发债看似多余。但这是典型的战略财务优化：以 AA/Aa1 最高投资级评级锁定历史低位的信用利差，降低加权平均资本成本，同时为 AI 领域的战略投资（已投入 OpenAI 300 亿、Anthropic 最高 100 亿、Intel 50 亿）和股东回报提供更多灵活性，且不耗尽手头现金。</p>\n<p><code>[AI债务热潮]</code> 英伟达并非孤例。Meta 和甲骨文各发行 250 亿美元、Alphabet 发行 200 亿美元、亚马逊单笔最高 370 亿美元——截至 5 月底全球 AI 相关债券发行已达 <strong>2360 亿美元</strong>，同比暴增 357%，摩根士丹利预测全年接近 5700 亿美元。AI 公司债市场已超美国银行业成为投资级债券最大板块。对企业 CFO，这轮发债潮传递的信号很明确：在 AI 基建军备竞赛中，<strong>债务融资比股权融资更便宜</strong>，只要信用评级撑得住，借债扩张比稀释股权更划算。对债券投资者，AI 概念债的超额认购表明科技公司信用质量已被市场接受为<strong>准主权级</strong>，下一步要看这些债募来的钱能否转化为可验证的 AI 收入。</p>\n<blockquote>\n<p><strong>signal ·</strong> 当现金流最充裕的公司都在大举借债，说明 AI 基建的资本消耗才刚刚进入下半场。</p>\n</blockquote>\n<h2 id=\"-openrouter-推出-fusion多模型并行模式挑战单模型霸权\">❯ OpenRouter 推出 Fusion，多模型并行模式挑战单模型霸权</h2>\n<p><code>[新推理范式]</code> OpenRouter 于 6 月 13 日发布 <strong>Fusion</strong>，一套多模型并行推理系统：用户请求被同时发送给多个模型组成的面板，再由一个”裁判”模型对比各输出后合成最终回答。据官方 DRACO 基准，最佳配置（Fable 5 + GPT-5.5，Opus 4.8 裁判）得分 <strong>69.0%</strong>，高于 Fable 5 单模型的 <strong>65.3%</strong>。Fusion 号称能以”一半价格实现 Fable 级智能”，但实际成本取决于面板配置——预算面板（Gemini 3 Flash + Kimi K2.6 + DeepSeek V4 Pro）确实比直接调用 Fable 5 便宜约一半，而高质量面板会更贵。</p>\n<p><code>[不是万能药]</code> Fusion 的基准测试目前仅覆盖深度研究类任务，不代表通用能力。早期用户的反馈显示其在编程、数学、SVG 生成等场景表现不稳定，且延迟明显高于单模型。OpenRouter 由 OpenSea 联合创始人 Alex Atallah 创立，2026 年 5 月刚获 CapitalG/Alphabet 的 1.13 亿美元投资，周处理超 <strong>2 万亿 tokens</strong>。</p>\n<p><code>[API层新战争]</code> Fusion 的创新不在于模型本身，而在于<strong>推理架构的编排</strong>——它把 LLM 调用从”选一个最好的”变成了”让多个模型协商出共识”。对开发者，应用设计时考虑的将不再是”哪个模型最强”，而是”哪个模型组合最适合我的场景”。对模型厂商，如果 Fusion 类服务证明了多模型路由胜过单模型调用，<strong>模型之间的差异化将从能力竞争转向面板组合中的补位竞争</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 未来的 AI 调用可能不再有赢家通吃，只有调度策略的优劣。</p>\n</blockquote>\n<h2 id=\"-字节跳动洽谈采购天数智芯-gpu国产芯片替代加速\">❯ 字节跳动洽谈采购天数智芯 GPU，国产芯片替代加速</h2>\n<p><code>[万级采购]</code> 据 Reuters 援引知情人士报道，字节跳动正与上海<strong>天数智芯（Iluvatar CoreX）</strong> 洽谈采购至少 <strong>5 万颗 AI 芯片</strong>，主要用于推理负载。同时字节还在考虑与百度达成交易采购 <strong>昆仑芯</strong>。天数智芯成立于 2015 年，2026 年 1 月在港交所上市，2025 年营收约 <strong>10.3 亿元</strong>，是国内首家实现训练与推理双量产的 GPU 公司。昆仑芯 2024 年出货 <strong>6.9 万片</strong>，位列国产第二，已提交港交所上市申请。</p>\n<p><code>[自研与外采双线]</code> 字节跳动的芯片策略是”自研+外采”并行：自研 SeedChip 团队已超千人，2026 年 3 月出样片；全年 AI 投入计划约 <strong>1600 亿元</strong>，其中芯片采购约 850 亿元。天数智芯将成为字节继华为昇腾、寒武纪之后的<strong>第三大国产 GPU 供应商</strong>，显示字节正在分散供应链风险，不将所有推理需求押注在单一国产平台。</p>\n<p><code>[国产化加速]</code> 自美国对华 AI 芯片出口管制层层加码以来，国产 GPU 市场份额已从 2022 年的 <strong>8.3%</strong> 升至 2024 年的 <strong>17.4%</strong>，预计 2029 年突破 50%。字节这次大规模采购，是<strong>需求侧最确定的信号</strong>：全球最大的 AI 应用公司之一正在认真地把国产芯片纳入生产级推理部署。对国产芯片厂商，字节的采购订单既是收入确认也是产品验证；对 NVIDIA，则即使禁令放松，部分推理市场已不可能回流。</p>\n<blockquote>\n<p><strong>signal ·</strong> 当字节开始用国产芯片跑推理，国产替代就从”备选方案”变成了”生产级默认项”。</p>\n</blockquote>\n<h2 id=\"-阿里巴巴据称以-15-亿美元洽谈收购生鲜电商朴朴\">❯ 阿里巴巴据称以 15 亿美元洽谈收购生鲜电商朴朴</h2>\n<p><code>[即时零售补位]</code> 据 Bloomberg 援引知情人士报道，阿里巴巴正洽谈以约 <strong>15 亿美元</strong>收购生鲜即时零售平台 <strong>朴朴超市</strong>。朴朴 2024 年营收约 <strong>300 亿元</strong>并首次实现全年盈利，在福州、深圳等 9 座城市运营 <strong>400 余个大型前置仓</strong>（800-1000 平方米），SKU 达 6000-8000，生鲜损耗率仅 1.5%。其大仓模式在业内被视为少数验证了盈利可能的前置仓形态。</p>\n<p><code>[阿里即时零售拼图]</code> 即时零售已被阿里列为淘天核心战略，设定了 2028 财年 GMV 超万亿的目标。淘宝闪购订单已达去年同期 2.7 倍，盒马 GMV 首破千亿——但阿里在华南尤其是福建市场存在明显空白。收购朴朴将一次补齐华南即时零售网络，同时获得其已验证的<strong>大仓运营能力</strong>，这是盒马此前尝试前置仓未成功的经验盲区。报价 15 亿美元低于此前市场传闻的 20-50 亿美元，也是阿里对估值预期的一种收紧姿态。</p>\n<p><code>[生鲜电商终局]</code> 这起潜在收购是中国即时零售”三国杀”的最新一步——美团 2 月以 7 亿美元吞下叮咚买菜，京东加速七鲜布局，阿里若拿下朴朴将形成三方各守一方的格局。对行业，独立生鲜电商的窗口已完全关闭：<strong>要么被巨头收购，要么在区域市场被供应链成本压垮</strong>。下一个看点是朴朴的大仓模式能否在阿里生态内加速复制到更多城市。</p>\n<blockquote>\n<p><strong>signal ·</strong> 生鲜即时零售从独立赛道变为了互联网超级生态的标准模块，再不站队就来不及了。</p>\n</blockquote>\n<h2 id=\"-小红书计划本月秘密递表港交所估值约-310-亿美元\">❯ 小红书计划本月秘密递表港交所，估值约 310 亿美元</h2>\n<p><code>[八年上市长跑]</code> 据 Bloomberg 援引知情人士报道，小红书计划在 <strong>6 月底前</strong>以秘密申请方式向香港联交所提交 IPO 申请。公司 2024 年净利润超 <strong>10 亿美元</strong>，是 2023 年 5 亿美元的两倍，2025 年利润预期约 30 亿美元。参考估值约 <strong>310 亿美元</strong>，较 2025 年底二级市场交易的 500 亿美元有所回落。小红书月活用户达 <strong>3.5 亿</strong>，日均使用时长超 74 分钟，以广告收入为主（约占 80%）。</p>\n<p><code>[从社区到商业]</code> 小红书曾于 2021 年计划赴美上市，因监管环境变化搁置。此后四年完成了从亏损到<strong>盈利</strong>的转型，2024 年净利润超 <strong>10 亿美元</strong>、电商 GMV 约 <strong>4000 亿元</strong>。2024 年提出”生活方式电商”定位，与天猫推出”红猫计划”、与京东推”红京计划”。投资方阵容豪华：腾讯、阿里、红杉中国、高瓴、DST Global 等均在其中。2025 年香港财政司司长陈茂波曾出席小红书香港办公室开幕仪式，信号意味明显。</p>\n<p><code>[中国互联网回港潮]</code> 小红书是最后一家尚未上市的头部中国互联网社区公司，其 IPO 将为 <strong>2018 年以来中国互联网公司回港潮画上句号</strong>。对投资者，小红书要回答的核心问题是：3.5 亿 MAU 的社区黏性能否在上市后维持，以及电商占比从 20% 向更高比例的爬升会否稀释社区调性。对行业，小红书的定价和首日表现将是<strong>中国消费互联网估值的一个新锚点</strong>。</p>\n<blockquote>\n<p><strong>signal ·</strong> 中国最后一家百亿美金级未上市社区公司终于走向公开市场，资本市场的反应将检验”社区+电商”故事还剩多少说服力。</p>\n</blockquote>"
};
